        HOWEVER_THE_PIONEER_MAY_HAVE_DROPPED_IT_IN                                    = 7415,  -- However, the pioneer may have dropped it in [Western Adoulin/Eastern Adoulin/Rala Waterways/Ceizak Battlegrounds/Yahse Hunting Grounds/Foret de Hennetiel/Morimar Basalt Fields/Yorcia Weald/Marjami Ravine/Kamihr Drifts/Sih Gates/Moh Gates/Cirdas Caverns/Dho Gates/Woh Gates/Outer Ra'Kaznar/Ra'Kaznar Inner Court/mei/mgk] instead.
        HEAD_TO_TO_FIND_AND_OBSERVE_A_MONSTER                                         = 7416,  -- Head to [Western Adoulin/Eastern Adoulin/Rala Waterways/Ceizak Battlegrounds/Yahse Hunting Grounds/Foret de Hennetiel/Morimar Basalt Fields/Yorcia Weald/Marjami Ravine/Kamihr Drifts/Sih Gates/Moh Gates/Cirdas Caverns/Dho Gates/Woh Gates/Outer Ra'Kaznar/Ra'Kaznar Inner Court/mei/mgk] to find and observe a monster located there. The assignment will be considered completed if you become the victim of a special attack from [an umbril/an umbril/a slug/a chapuli/a chapuli/a craklaw/a matamata/a snapweed/a tulfaire/a raaz/a crakklaw/a matamata/an aceux/Dho Gates/Woh Gates/Outer Ra'Kaznar/Ra'Kaznar Inner Court/mei/mgk].
        NOT_JUST_ANY_SPECIAL_ATTACK_WILL_DO_YOU                                       = 7417,  -- Not just any special attack will do. You must be the victim of a special attack that the Mummers' Coalition can use in one of its myriad forms of artistic expression.
        ALTERNATIVELY_THE_OBJECTIVE_MAY_ALSO_BE_COMPLETED_BY_6                        = 7418,  -- Alternatively, the objective may also be completed by being the victim of a special attack in the creatures' secondary habitat of [Western Adoulin/Eastern Adoulin/Rala Waterways/Ceizak Battlegrounds/Yahse Hunting Grounds/Foret de Hennetiel/Morimar Basalt Fields/Yorcia Weald/Marjami Ravine/Kamihr Drifts/Sih Gates/Moh Gates/Cirdas Caverns/Dho Gates/Woh Gates/Outer Ra'Kaznar/Ra'Kaznar Inner Court/mei/mgk], which is located nearby.
        YOU_MUST_HEAD_TO_THE_FRONTIER_STATION_IN                                      = 7419,  -- You must head to the frontier station in [Western Adoulin/Eastern Adoulin/Rala Waterways/Ceizak Battlegrounds/Yahse Hunting Grounds/Foret de Hennetiel/Morimar Basalt Fields/Yorcia Weald/Marjami Ravine/Kamihr Drifts/Sih Gates/Moh Gates/Cirdas Caverns/Dho Gates/Woh Gates/Outer Ra'Kaznar/Ra'Kaznar Inner Court/mei/mgk] and cheer up the staff located there. The assignment will be considered completed if you successfully raise their spirits.
        ALTERNATIVELY_THE_OBJECTIVE_MAY_ALSO_BE_COMPLETED_BY_7                        = 7420,  -- Alternatively, the objective may also be completed by raising the spirits of those in the nearby area of [Western Adoulin/Eastern Adoulin/Rala Waterways/Ceizak Battlegrounds/Yahse Hunting Grounds/Foret de Hennetiel/Morimar Basalt Fields/Yorcia Weald/Marjami Ravine/Kamihr Drifts/Sih Gates/Moh Gates/Cirdas Caverns/Dho Gates/Woh Gates/Outer Ra'Kaznar/Ra'Kaznar Inner Court/mei/mgk], as they are in need of encouragement as well.
        WHAT_EXPANSION_PLAN_WILL_YOU_COALITION_FLAG_SIGNBOARD                         = 7421,  -- What expansion plan will you [vote for/view]? Coalition flag. Signboard. Emblem. Second floor. Adoulinian flag. Main terrace. Bay roof. Main chimney. [None of these/None of these].
        COALITION_PERSONAL_FAME_ACQUIRED_PTS_TOTAL_PERSONAL_FAME                      = 7422,  -- [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition: Personal fame acquired: # pts. Total personal fame: # pts.
        COALITION_ADDITIONAL_COALITION_DEVELOPMENT_VALUE_PTS_TOTAL_COALITION          = 7423,  -- [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition: Additional coalition development value: # pts. Total coalition development value%s.
        COALITION_EXPANSION_PLAN_ADDITIONAL_REFERENDUM_VALUE_PTS_TOTAL                = 7424,  -- [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition: [coalition fla/sign board/emblem/second floor/Adoulinian flag/main terrace/bay roof/main chimney] expansion plan: Additional referendum value: # pts. Total referendum value: # pts.
        WE_ALSO_GIVE_ADDITIONAL_REWARDS_BASED_ON_THE                                  = 7425,  -- We also give additional rewards based on the degree of construction or the durability of the facility to those pioneers brave enough to travel far distances or into particularly dangerous territory.
        WE_ALSO_GIVE_ADDITIONAL_REWARDS_BASED_ON_THE_2                                = 7426,  -- We also give additional rewards based on the extent of the survey to those pioneers brave enough to travel far distances or into particularly dangerous territory.
        IS_THERE_ANYTHING_YOU_D_LIKE_TO_KNOW                                          = 7427,  -- [Why, hello there, my dear pioneer!/Good day to you./Hello, pioneer./Welcome to our establishmentaru!/I hope you're having a marvelous-warvelous day!/Welcome back!] Is there anything you'd like to know about the [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition?
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_THE                                         = 7428,  -- What would you like to know about? The [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition's role. The state of the [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition. Types of coalition assignments. Current expansion plans. Coalition referendum support. Your current standing. Nothing.
        THE_PIONEERS_COALITION_CONTRIBUTES_TO_THE_COLONIZATION_EFFORT                 = 7429,  -- The Pioneers' Coalition contributes to the colonization effort mainly by cultivating uninhabitable territory and preparing the necessary resources to do so.
        IT_WOULD_TAKE_NO_STRETCH_OF_THE_IMAGINATION                                   = 7430,  -- It would take no stretch of the imagination to say that our coalition is the standard-bearer for the whole movement, what with all the brave young men and women that swell our ranks.
        THE_MAESTER_WHO_LEADS_OUR_FAMILY_OF_SETTLERS                                  = 7431,  -- The maester who leads our family of settlers is Lhe Lhangavo from the Order of Karieyh. She's possibly the most passionate of any order leader, and certainly one of the most caring. She's always looking out for her subordinates.
        THE_PEACEKEEPERS_COALITION_HAS_THE_MOST_SELF_EXPLANATORY                      = 7432,  -- The Peacekeepers' Coalition has the most self-explanatory name I'm sure you've ever heard. We work towards making Adoulin a safer place.
        WE_RE_COMPOSED_OF_ONLY_THE_MOST_DEDICATED                                     = 7433,  -- We're composed of only the most dedicated and dutiful individuals--people willing to give their lives to protect this town and its populace.
        THE_GREAT_THOUGH_OFTEN_GRUMPY_GRATZIGG_IS_OUR                                 = 7434,  -- The great--though often grumpy--Gratzigg is our maester, but despite his sour demeanor, he's the most loyal of anyone in the Twelve Orders. His love for Adoulin has saved it from utter despair more times than I care to remember.
        THE_COURIERS_COALITION_DOES_ITS_PART_BY_TRANSPORTING                          = 7435,  -- The Couriers' Coalition does its part by transporting supplies to the front lines. We also ensure the integrity of every shipment's cargo.
        WE_RE_VERY_PUNCTUAL_AND_REALLY_STRICT_ABOUT                                   = 7436,  -- We're very punctual and really strict about getting our deliveries right. We have the reputation of being uptight because of it, but it's those qualities that keep the pioneering movement going.
        REGINALD_SERVES_AS_OUR_MAESTER_HE_MAY_NOT                                     = 7437,  -- Reginald serves as our maester. He may not be the most talkative person you've ever met, but just try to find a more gentlemanly gentleman among the Twelve Orders.
        THE_SCOUTS_COALITION_GATHERS_INTELLIGENCE_FROM_ALL_OVER                       = 7438,  -- The Scouts' Coalition gathers intelligence from all over the continentaru and analyzes unknown materials to further the colonization movement.
        THE_KNOWLEDGE_OUR_COALITION_ACCRUES_COUPLED_WOUPLED_WITH                      = 7439,  -- The knowledge our coalition accrues, coupled-woupled with our innate knack for careful archival supervision, makes us indispensable in this era.
        OUR_MAESTARU_MARGRET_BELONGS_TO_THE_ORDER_OF                                  = 7440,  -- Our maestaru, Margret, belongs to the Order of Haverton. Her sheer brilliance-williance makes appetizers out of even the most difficult problems, so it's no wonder that she is seen as one of the greatest minds in Adoulin.
        THE_INVENTORS_COALITION_MAINLY_SUPPORTARUS_PIONEERS_AND_THE                   = 7441,  -- The Inventors' Coalition mainly supportarus pioneers and the colonization of Ulbuka through the development of tools and equipment.
        WE_PROVIDE_AN_ECONOMIC_FOUNDATION_WATION_FOR_THE                              = 7442,  -- We provide an economic foundation-wation for the city and the pioneering movement by using the materials pioneers bring us to create new foodstuffs that can last an ocean voyage, along with new articles to outfitaru explorers.
        OUR_MAESTER_IS_THE_ONE_AND_ONLY_AMCHUCHU                                      = 7443,  -- Our maester is the one-and-only Amchuchu from the Order of Orvail. Her skills and mind are more renowned than possibly any other maester in Adoulin's history-wistory, making her one of our most talented technicians.
        THE_NUMBER_ONE_CONCERN_FOR_THE_MUMMERS_COALITION                              = 7444,  -- The number one concern for the Mummers' Coalition is pioneer morale.
        IT_MAY_SEEM_LIKE_ALL_WE_DO_IS                                                 = 7445,  -- It may seem like all we do is spout japes and cavort about, but there is a method to our apparent madness. Soothing the spirits of pioneers has a proven economic benefit, so expect to see Mummer-sponsored events for some time to come.
        FLAVIRIA_FROM_THE_ORDER_OF_THURANDAUT_HEADS_OUR                               = 7446,  -- Flaviria from the Order of Thurandaut heads our troupe, and I've never seen anyone who can spin a yarn or tell a joke quite like her. It's obvious that someone with her personality would be loved by both the nobility and common folk.
        THE_COALITION_IS_CURRENTLY_RANK_NUMBER                                        = 7447,  -- The [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition is currently rank number #.
        ACCORDING_TO_THE_MOST_RECENT_SURVEYS_THIS_COALITION                           = 7448,  -- According to the most recent surveys, this coalition [is a blight on the city./is nothing to write home about./isn't half bad./is expanding nicely./is a credit to the city./puts others to shame!/is a paragon of prosperity!] [You might want to try to remedy that./Keep trying./Your efforts are starting to pay off./That said, you're still only halfway to the top./Feel free to gloat about your accomplishments./I hope you're not afraid of heights, because you're incredibly close to the top!/How's the view from the top? Great? Then keep up the excellent work!]
        YOU_VE_ALL_BEEN_AT_ACCOMPLISHING_YOUR_COALITION                               = 7449,  -- You've all been [abysmal/uninspiring/decent/remarkable/positively miraculous] at accomplishing your coalition assignments. Our coalition's rank [will almost certainly fall/may fall/will probably stay about the same/might rise/will almost certainly rise] after the next evaluation.
        YOU_WANT_TO_KNOW_ABOUT_THE_SERVICES_OFFERED                                   = 7450,  -- You want to know about the services offered by the [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition? Well, we offer[.../ nothing at the moment. Sorry.]
        ID_7451                                                                       = 7451,  -- [- Gathering Goods/- Gathering Goods II/- Gathering Equipment/- Gathering Technique Knowledge/- Colonization Support Provisions/- Gathering Goods III/- Gathering Equipment II/- Colonization Support Provisions II/- Gathering Technique Knowledge II][/ and our overly cheerful trailblazing attitude...not that the last is really a service./nothing at this time.]
        ID_7452                                                                       = 7452,  -- [- Traditional Armor/- Traditional Weaponry/- Traditional Armor II/- Frontline Provisions/- Traditional Weaponry II/- Traditional Armor III/- Traditional Armor IV/- Traditional Armor V/- Traditional Armor VI][/ and our usual killjoy meddling...if you call that a service./no services at this time.]
        ID_7453                                                                       = 7453,  -- [- Travel Assistance Provisions/- Temporary Warp Runes/- Town Movement Speed Enhancement/- Delivery Personnel Increase/- Kinetic Unit Cost Adjustment/- Temporary Warp Runes II/- Town Movement Speed Enhancement II/- Delivery Personnel Increase II/- Kinetic Unit Cost Adjustment II][/ and our compulsive attention to the time...if you can even call that a service./no services at this time.]
        ID_7454                                                                       = 7454,  -- [- Maps/- Map Marking/- Colonization Intelligence/- Ergon Locus Intelligence/- Library Cards/- Map Marking II/- Spoils of War Intelligence/- Ergon Locus Intelligence II/- Spoils of War Intelligence II][/ and our absolutely incessant snooping...if you're into that kinda thing./no services at this time.]
        ID_7455                                                                       = 7455,  -- [- Ergon Tinctures/- Synthesis Support Provisions/- Arcane Glyptics Price Reduction/- Arcane Glyptics Materials/- Growth Agents and Materials/- Synthesis Support Provisions II/- Arcane Glyptics Price Reduction II/- Growth Agents and Materials Price Reduction/- Travel Provisions][/ and our annual Girls of Science calendar...if you can get your hands on a copy./no services at this time.]
        ID_7456                                                                       = 7456,  -- [- Guess That Number (Game)/- Boom or Bust (Game)/- On The Dot (Game)/- Cascade (Game)/- Mummers' Medal Prizes/- Box of Fortune (Game)/- Mummers' Medal Prizes II/- Mummers' Medal Prizes III/- Three-Card Circus (Game)][/ and our usual array of god-awful puns...if you can stand that particular service./no services at this time.]
        BASED_ON_THE_EXPANSION_OF_THE_COALITION_IONIS                                 = 7457,  -- Based on the expansion of the [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition, Ionis provides[.../ no additional benefits.]
        ID_7458                                                                       = 7458,  -- [/- Minor Attack Enhancement/- Minor Magic Attack Bonus/- Minor Gathering Fatigue Reduction/- Minor Gathering Efficacy Enhancement/- Moderate Attack Enhancement/- Moderate Magic Attack Bonus/- Moderate Gathering Fatigue Reduction /- Moderate Gathering Efficacy Enhancement][/ in addition to its normal benefits./no additional benefits.]
        ID_7459                                                                       = 7459,  -- [/- Minor Defense Enhancement/- Minor Magic Defense Bonus/- Minor HP and MP Recovery Enhancement/- Minor Enhancement to Max HP and MP/- Moderate Defense Enhancement/- Moderate Magic Defense Bonus/- Moderate HP and MP Recovery Enhancement/- Moderate Enhancement to Max HP and MP][/ in addition to its normal benefits./no additional benefits.]
        ID_7460                                                                       = 7460,  -- [/- Minor Accuracy and Magic Accuracy Enhancement/- Minor Evasion and Magic Evasion Enhancement/- Minor Critical Hit Rate Increase/- Minor Haste Effect/- Moderate Accuracy and Magic Accuracy Enhancement/- Moderate Evasion and Magic Evasion Enhancement/- Moderate Critical Hit Rate Increase/- Moderate Haste Effect][/ in addition to its normal benefits./no additional benefits.]
        ID_7461                                                                       = 7461,  -- [/- Minor Save TP Effect/- Minor Conserve MP Effect/- Minor Fast Cast Effect/- Minor Resistance Increase to All Status Ailments/- Moderate Save TP Effect/- Moderate Conserve MP Effect/- Moderate Fast Cast Effect/- Moderate Resistance Increase to All Status Ailments][/ in addition to its normal benefits./no additional benefits.]
        ID_7462                                                                       = 7462,  -- [/- Minor Crystal Obtainment Rate Increase/- Minor Material Loss Rate Reduction/- Minor Synthesis Skill Gain Rate Increase/- Minor Synthesis Success Rate Increase/- Moderate Crystal Obtainment Rate Increase/- Moderate Material Loss Rate Reduction/- Moderate Synthesis Skill Gain Rate Increase/- Moderate Synthesis Success Rate Increase][/ in addition to its normal benefits./no additional benefits.]
        ID_7463                                                                       = 7463,  -- [/- Minor Combat Skill Gain Rate Increase/- Minor Magic Skill Gain Rate Increase/- Minor Experience Point Bonus/- Minor Reward Obtainment Rate Increase/- Moderate Combat Skill Gain Rate Increase/- Moderate Magic Skill Gain Rate Increase/- Moderate Experience Point Bonus/- Moderate Reward Obtainment Rate Increase][/ in addition to its normal benefits./no additional benefits.]
        WHAT_ASSIGNMENTS_WILL_YOU_ASK_ABOUT_PROCURING_RESOURCES                       = 7464,  -- What assignments will you ask about? Procuring resources. Clearing the way. Preserving the peace. Patrols. Base provisions. Delivering supplies. Frontline support. Land surveys. Component analysis. Gathering materials. Recovering lost articles. Behavioral research. Morale boosting. Nothing.
        HEAD_OUT_INTO_THE_WORLD_AND_GATHER_VITAL                                      = 7465,  -- Head out into the world and gather vital pioneering resources via methods such as mining and logging. Simply purchasing the supplies tells the coalition nothing of your abilities, however, and those who do will receive no remuneration.
        IT_MAY_SEEM_LIKE_A_THANKLESS_JOB_BUT                                          = 7466,  -- It may seem like a thankless job, but the erection of coalition expansions and frontier stations demands constant provisioning, so it is not a task to be taken lightly.
        NATURAL_OBSTACLES_POP_UP_FROM_TIME_TO_TIME                                    = 7467,  -- Natural obstacles pop up from time to time, and pioneers are often asked to engage in a bit of bushwhacking to clear them away so the colonization movement can proceed. The only way to be officially recognized for such feats, though, is by participating in Colonization Reives.
        THE_PERILS_ARE_APTLY_NAMED_FOR_MANY_PIONEERS                                  = 7468,  -- The perils are aptly named, for many pioneers have fallen in attempts to rid the land of them. So many, in fact, that Maester Lhangavo was bereft of a few fur clumps for some time worrying over the issue.
        PEACE_IN_ADOULIN_IS_A_PRECARIOUS_THING_FIENDS                                 = 7469,  -- Peace in Adoulin is a precarious thing. Fiends could assault the city at any moment, which is why we need to nip this problem in the bud. Join Lair Reives to eliminate their breeding grounds and contribute to the colonization effort.
        IF_ONLY_THE_INSTINCT_TO_REBUILD_THEIR_HOMES                                   = 7470,  -- If only the instinct to rebuild their homes were not so engrained in these hellions, life would be much easier for us. Sadly, you'll need to participate in these reives periodically in order to keep Ulbuka habitable.
        WHILE_THE_PEACEKEEPERS_COALITION_OFTEN_MAKES_ITS_ROUNDS                       = 7471,  -- While the Peacekeepers' Coalition often makes its rounds in the city itself, these patrols will take you to specific jungle locales for the express purpose of culling unwanted pests. Make sure to slay your quota, though, or you won't receive any recognition for your deeds.
        GIVE_ADOULIN_S_POPULATION_SOME_PEACE_OF_MIND                                  = 7472,  -- Give Adoulin's population some peace of mind by embarking on these expeditions every so often. Also, rumors about far more terrifying beasts are likely to surface the further we progress into Ulbuka's interior, but as long as you stick to your duties, you should have no reason to fear them.
        FOR_THESE_ASSIGNMENTS_YOU_LL_NEED_TO_TRANSPORT                                = 7473,  -- For these assignments, you'll need to transport provisions to the sites of future frontier stations. You can now use waypoints and still receive commendations, but be prepared to hear stories about back in my day, we had to walk all the way out and back on our own two feet, from some wily veterans.
        FRONTIER_STATIONS_ARE_PARAMOUNT_TO_SUSTAINING_THE_COLONIZATION                = 7474,  -- Frontier stations are paramount to sustaining the colonization effort. Tasks of greater magnitude can't even begin without one, so building these structures should always be a priority.
        YOU_WILL_SOMETIMES_BE_CHARGED_WITH_CARRYING_SUPPLIES                          = 7475,  -- You will sometimes be charged with carrying supplies from specific frontier stations to the Couriers' Coalition.
        BY_SUPPLIES_I_MEAN_ONES_OBTAINED_IN_THE                                       = 7476,  -- By supplies, I mean ones obtained in the jungle through pioneering. Yes, acting as a beast of burden may not be the most glamorous duty, but it is a vital one if we're to improve the coalitions and keep Adoulin economically stable.
        THE_MOST_EFFECTIVE_WAY_OF_SUPPORTING_THOSE_RISKING                            = 7477,  -- The most effective way of supporting those risking their lives on the front lines is by supplying designated frontier bivouacs with the necessary provisions. While it may go against previous Couriers' Coalition policy, the use of waypoints is henceforth permitted on this type of assignment.
        TRUTH_BE_TOLD_FRONTIER_BIVOUACS_ARE_NOT_AS                                    = 7478,  -- Truth be told, frontier bivouacs are not as developed as their station counterparts, but they still play an important role in the colonization of the continent. If they don't receive provisions regularly, our supply lines to the stations will wither and die.
        TRAVEL_TO_PLACES_UNKNOWN_IN_SEARCH_OF_ERGON                                   = 7479,  -- Travel to places unknown in search of ergon loci, areas overflowing with natural energy. While some say it's the journey--not the destination--that matters, failing to survey even a single locus will leave you both depleted of energy and empty-handed.
        THE_POTENCY_OF_AN_ERGON_TINCTURE_IS_HIGHLY                                    = 7480,  -- The potency of an ergon tincture is highly dependent upon the strength of the ergon locus from which it's extracted, so a thorough investigation must be made into each location if we're to successfully use this trump card we've created.
        COMPLETION_OF_THESE_ASSIGNMENTS_MEANS_PROVIDING_THE_SCOUTS                    = 7481,  -- Completion of these assignments means providing the Scouts' Coalition--and no others, for they are the only ones to possess the proper facilities--with unique and extraordinary materials from certain territories.
        THE_JUNGLE_IS_TEEMING_WITH_OBSCURE_AND_UNFAMILIAR                             = 7482,  -- The jungle is teeming with obscure and unfamiliar substances, and from them we hope to derive more powerful and effective materials with which to aid the colonization effort. Science waits for no man, however, and without periodic deliveries of new samples, our research will stagnate.
        THE_PROPER_EQUIPMENT_AND_TOOLS_ARE_INSTRUMENTAL_IN                            = 7483,  -- The proper equipment and tools are instrumental in the colonization movement's progress--and the Inventors' Coalition apparently wants to be the one to corner the market.
        WHILE_THE_INVENTORS_COALITION_DOESN_T_PARTICULARLY_CARE                       = 7484,  -- While the Inventors' Coalition doesn't particularly care how you obtain what they ask for once you're in the specified location, they are quite picky about the number you obtain and the fact that you can't deliver to anyone else.
        PIONEERS_ARE_AN_INTREPID_BAND_OF_ADVENTURERS_BUT                              = 7485,  -- Pioneers are an intrepid band of adventurers, but the nature of their trade makes them prone to losing personal effects. Pick up any lost articles in the territory to which you are dispatched and return for a reward along with a pat on the back.
        THIS_IS_PROBABLY_THE_LEAST_GARISH_SERVICE_THE                                 = 7486,  -- This is probably the least garish service the Mummers' Coalition provides, but it's one for which pioneers throughout Adoulin are eternally grateful.
        THOUGH_THEY_MAY_NOT_BE_THE_FRIENDLIEST_OF                                     = 7487,  -- Though they may not be the friendliest of Ulbuka's inhabitants, that doesn't mean the fiends who populate the continent can't teach us a thing or two. Research designated beasts by personally experiencing their special attacks and report what they taught you...if you live to tell the tale.
        THE_MUMMERS_COALITION_IS_CONSTANTLY_SEARCHING_FOR_ITS                         = 7488,  -- The Mummers' Coalition is constantly searching for its muse in all manner of sources, one being the myriad monsters scattered throughout the jungle. Investigating monsters' behavior may be just the inspiration they need to concoct new dances, gags, and events!
        THE_ISOLATION_OF_THE_FRONTIER_CAN_EAT_AT                                      = 7489,  -- The isolation of the frontier can eat at even the most independent of us, which is why it's important to give our pioneers something to cheer about. Head to specified frontier stations and lift the spirits of the workers there! Just remember that if they don't smile, you don't get rewarded.
        DANCE_SING_SHOUT_OR_GENERALLY_MAKE_A_FOOL                                     = 7490,  -- Dance, sing, shout, or generally make a fool of yourself. It doesn't matter how you do it, as long as you can make them laugh and forget their cares for a few moments.
        THIS_COALITION_IS_EDIFIED_AS_MUCH_AS_POSSIBLE                                 = 7491,  -- This coalition is edified as much as possible, and therefore we have no plans to expand.
        WHICH_PLAN_DO_YOU_WANT_TO_LEARN_ABOUT                                         = 7492,  -- Which plan do you want to learn about? Coalition flag. Signboard. Emblem. Second floor. Adoulinian flag. Main terrace. Bay roof. Main chimney. None.
        IF_THE_EXPANSION_PLAN_SUCCEEDS_THE_STAFF_IN                                   = 7493,  -- If the [/coalition flag/signboard/emblem/second floor/Adoulinian flag/main terrace/bay roof/main chimney] expansion plan succeeds, the staff in charge of [Gathering Goods/Gathering Goods II/Gathering Equipment/Gathering Technique Knowledge/Colonization Support Provisions/Gathering Goods III/Gathering Equipment II/Colonization Support Provisions II/Gathering Technique Knowledge II] will [increase in number/expand throughout the continent/provide additional services/be more successful].
        FURTHER_IONIS_EFFECTS_WILL_EXPAND_TO_INCLUDE                                  = 7494,  -- Further, Ionis effects will expand to include [/Minor Attack Enhancement/Minor Magic Attack Bonus/Minor Gathering Fatigue Reduction/Minor Gathering Efficacy Enhancement/Moderate Attack Enhancement/Moderate Magic Attack Bonus/Moderate Gathering Fatigue Reduction/Moderate Gathering Efficacy Enhancement].
        IF_THE_EXPANSION_PLAN_SUCCEEDS_THE_STAFF_IN_2                                 = 7495,  -- If the [/coalition flag/signboard/emblem/second floor/Adoulinian flag/main terrace/bay roof/main chimney] expansion plan succeeds, the staff in charge of [Traditional Armor/Traditional Weaponry/Traditional Armor II/Frontline Provisions/Traditional Weaponry II/Traditional Armor III/Traditional Armor IV/Traditional Armor V/Traditional Armor VI] will [increase in number/expand throughout the continent/provide additional services/be more successful].
        FURTHER_IONIS_EFFECTS_WILL_EXPAND_TO_INCLUDE_2                                = 7496,  -- Further, Ionis effects will expand to include [/Minor Defense Enhancement/Minor Magic Defense Bonus/Minor HP and MP Recovery Enhancement/Minor Enhancement to Max HP and MP/Moderate Defense Enhancement/Moderate Magic Defense Bonus/Moderate HP and MP Recovery Enhancement/Moderate Enhancement to Max HP and MP].
        IF_THE_EXPANSION_PLAN_SUCCEEDS_THE_STAFF_IN_3                                 = 7497,  -- If the [/coalition flag/signboard/emblem/second floor/Adoulin flag/main terrace/bay roof/main chimney] expansion plan succeeds, the staff in charge of [Travel Assistance Provisions/Temporary Warp Runes/Town Movement Speed Enhancement/Delivery Personnel Increase/Kinetic Unit Cost Adjustment/Temporary Warp Runes II/Town Movement Speed Enhancement II/Delivery Personnel Increase II/Kinetic Unit Cost Adjustment II] will [increase in number/expand throughout the continent/provide additional services/be more successful].
        FURTHER_IONIS_EFFECTS_WILL_EXPAND_TO_INCLUDE_3                                = 7498,  -- Further, Ionis effects will expand to include [/Minor Accuracy and Magic Accuracy Enhancement/Minor Evasion and Magic Evasion Enhancement/Minor Critical Hit Rate Increase/Minor Haste Effect/Moderate Accuracy and Magic Accuracy Enhancement/Moderate Evasion and Magic Evasion Enhancement/Moderate Haste Effect].
        IF_THE_EXPANSION_PLAN_SUCCEEDS_THE_STAFF_IN_4                                 = 7499,  -- If the [/coalition flag/signboard/emblem/second floor/Adoulinian flag/main terrace/bay roof/main chimney] expansion plan succeeds, the staff in charge of [Maps/Map Marking/Colonization Intelligence/Ergon Locus Intelligence/Library Cards/Map Marking II/Spoils of War Intelligence/Ergon Locus Intelligence II/Spoils of War Intelligence II] will [increase in number/expand throughout the continent/provide additional services/be more successful].
        FURTHER_IONIS_EFFECTS_WILL_EXPAND_TO_INCLUDE_4                                = 7500,  -- Further, Ionis effects will expand to include [/Minor Save TP Effect/Minor Conserve MP Effect/Minor Fast Cast Effect/Minor Resistance Increase to All Status Ailments/Moderate Save TP Effect/Moderate Conserve MP Effect/Moderate Fast Cast Effect/Moderate Resistance Increase to All Status Ailments].
        IF_THE_EXPANSION_PLAN_SUCCEEDS_THE_STAFF_IN_5                                 = 7501,  -- If the [/coalition flag/signboard/emblem/second floor/Adoulinian flag/main terrace/bay roof/main chimney] expansion plan succeeds, the staff in charge of [Ergon Tinctures/Synthesis Support Provisions/Arcane Glyptics Price Reduction/Arcane Glyptics Materials/Growth Agents and Materials/Synthesis Support Provisions II/Arcane Glyptics Price Reduction II/Growth Agents and Materials Price Reduction/Travel Provisions] will [increase in number/expand throughout the continent/provide additional services/be more successful].
        FURTHER_IONIS_EFFECTS_WILL_EXPAND_TO_INCLUDE_5                                = 7502,  -- Further, Ionis effects will expand to include [/Minor Crystal Obtainment Rate Increase/Minor Material Loss Rate Reduction/Minor Synthesis Skill Gain Rate Increase/Minor Synthesis Success Rate Increase/Moderate Crystal Obtainment Rate Increase/Moderate Material Loss Rate Reduction/Moderate Synthesis Skill Gain Rate Increase/Moderate Synthesis Success Rate Increase].
        IF_THE_EXPANSION_PLAN_SUCCEEDS_THE_STAFF_IN_6                                 = 7503,  -- If the [/coalition flag/signboard/emblem/second floor/Adoulinian flag/main terrace/bay roof/main chimney] expansion plan succeeds, the staff in charge of [Guess That Number (Game)/Boom or Bust (Game)/On The Dot (Game)/Cascade (Game)/Mummers' Medal Prizes/Box of Fortune (Game)/Mummers' Medal Prizes II/Mummers' Medal Prizes III/Three-Card Circus (Game)] will [increase in number/expand throughout the continent/provide additional services/be more successful].
        FURTHER_THE_IONIS_EFFECTS_WILL_EXPAND_TO_INCLUDE                              = 7504,  -- Further, the Ionis effects will expand to include [/Minor Combat Skill Gain Rate Increase Minor Magic Skill Gain Rate Increase/Minor Experience Point Bonus/Minor Reward Obtainment Rate Increase/Moderate Combat Skill Gain Rate Increase/Moderate Magic Skill Gain Rate Increase/Moderate Experience Point Bonus/Moderate Reward Obtainment Rate Increase].
        THE_STRUCTURE_MOST_MEMBERS_WANT_TO_SEE_ADDED                                  = 7505,  -- The structure most members want to see added to the [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition is...
        A_2                                                                           = 7506,  -- A[ coalition flag/ signboard/n emblem/ second floor/n Adoulinian flag/ main terrace/ bay roof/ main chimney]! [It leads by default since there aren't any other proposals./Many more people have voted for it than any other structure./A good number of people have chosen it over the other options./Not by much, however.]
        YOUR_CONTRIBUTIONS_TO_THE_COALITION_HAVE_EARNED_YOU                           = 7507,  -- Your contributions to the [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition have earned you the title of...
        ID_7508                                                                       = 7508,  -- [Pioneer/Peacekeeper/Courier/Scout/Inventor/Mummer] [Petitioner/Probationer/Disciple/Contributor/Partner/Advisor/Magnate/Legend]! [You're off to a swell start!/Congratulations, but you're not out of the woods yet./They've given you their trust. Now it's time to prove they were right to do so!/You're in the position to start making a big difference in Adoulin!/Talent flows unabated from your every pore!/Other pioneers must trample each other seeking your sage advice./One could very well say that the colonization effort revolves around you!/Your exploits will surely be etched in the annals of this continent's history!]
        A_REIVE_HAS_STARTED_AT                                                        = 7509,  -- A [Lair/Colonization/Wildskeeper] Reive has started at ([A/B/C/D/E/F/G/H/I/J/K/L/M/N/O]-#).
        WHAT_WILL_YOU_DO_TURN_TAIL_PRESS_ONWARD                                       = 7510,  -- What will you do? Turn tail. Press onward. Check battle conditions.
        THE_CURRENT_BATTLE_CONDITIONS_ARE_FINISH_CURRENTLY_CURRENTLY                  = 7511,  -- The current battle conditions are: Finish. Currently: #.#% Currently: Unknown # [min. ago/hr. ago]: #.#% # [min. ago/hr. ago]: Unclear. # [min. ago/hr. ago]: #.#% # [min. ago/hr. ago]: Unclear. # [min. ago/hr. ago]: #.#% # [min. ago/hr. ago]: Unclear. # [min. ago/hr. ago]: #.#% # [min. ago/hr. ago]: Unclear. # [min. ago/hr. ago]: #.#% # [min. ago/hr. ago]: Unclear. # [min. ago/hr. ago]: #.#% # [min. ago/hr. ago]: Unclear. # [min. ago/hr. ago]: #.#% # [min. ago/hr. ago]: Unclear. # [min. ago/hr. ago]: #.#% # [min. ago/hr. ago]: Unclear. # [min. ago/hr. ago]: #.#% # [min. ago/hr. ago]: Unclear. Change time interval.
        WHAT_TIME_INTERVAL_KEEP_THE_CURRENT_INTERVAL_MINS                             = 7512,  -- What time interval? Keep the current interval ([5/10/20/30/60] mins.). Five minutes. Ten minutes. Twenty minutes. Thirty minutes. Sixty minutes.
        AS_OF_AGO_S_HP_IS_AT                                                          = 7513,  -- As of # [minute/hour][/s] ago, [Colkhab/Tchakka/Achuka/Yumcax/Hurkan/Kumhau]'s HP is at #.#%.
        UNABLE_TO_CONFIRM_S_EXISTENCE_AS_OF_AGO                                       = 7514,  -- Unable to confirm [Colkhab/Tchakka/Achuka/Yumcax/Hurkan/Kumhau]'s existence as of # [minute/hour][/s] ago.
        DEBUG_FLAG_RAISED_KUPO                                                        = 7515,  -- (DEBUG) Flag raised, kupo!
        WELCOME_MASTER_THIS_IS_YOUR_HOME_THE_MOG                                      = 7516,  -- Welcome, Master! This is your home, the Mog House, kupo!
        I_M_A_MOOGLE_WE_MOOGLES_LIKE_TAKING                                           = 7517,  -- I'm a moogle! We moogles like taking care of houses and items! Nice to meet you, kupo!
        I_LL_TELL_YOU_ALL_ABOUT_YOUR_MOG                                              = 7518,  -- I'll tell you all about your Mog House, kupo!
        FIRST_THE_BASICS_KUPO_OPEN_YOUR_MAIN_MENU                                     = 7519,  -- First, the basics, kupo! Open your main menu, Master. The button at the very bottom changes to Mog House when you're in your Mog House, kupo!
        PRESS_IT_AND_THE_MOG_HOUSE_MENU_WILL                                          = 7520,  -- Press it and the Mog House menu will appear! Everything you can do in your Mog House is there, kupo!
        THERE_ARE_LOTS_OF_THINGS_YOU_CAN_DO                                           = 7521,  -- There are lots of things you can do in your Mog House, kupo! It can be too much for some masters, kupo...
        SO_I_LL_TEACH_YOU_ABOUT_EACH_ONE                                              = 7522,  -- So I'll teach you about each one of them! Ask me what you want to know about, kupo!
        CHOOSE_THE_MOG_HOUSE_COMMAND_YOU_WANT_TO                                      = 7523,  -- Choose the Mog House command you want to know about, kupo!
        WHAT_DO_YOU_WANT_TO_KNOW_ABOUT_THE                                            = 7524,  -- What do you want to know about? The Mog Safe. Storage. The Delivery Box. Changing jobs. Gardening. Changing the layout. Mog House invitations. I got it, thanks, kupo!
        THE_MOG_SAFE_IS_WHERE_I_KEEP_ITEMS                                            = 7525,  -- The Mog Safe is where I keep items that you can't carry! It's an especially secure and solid safe, kupo!
        YOU_CAN_ONLY_PUT_SO_MANY_ITEMS_IN                                             = 7526,  -- You can only put so many items in it, kupo... But I'll guard them even if it means my life, kupo!
        THE_DELIVERY_BOX_IS_WHERE_YOU_CAN_SEND                                        = 7527,  -- The Delivery Box is where you can send letters to friends and receive items from various places, kupo!
        YOU_SHOULD_TAKE_THE_ITEMS_FROM_YOUR_DELIVERY                                  = 7528,  -- You should take the items from your Delivery Box and put them in your inventory when they arrive, kupo!
        IF_YOUR_DELIVERY_BOX_IS_FULL_NO_MORE                                          = 7529,  -- If your Delivery Box is full, no more deliveries can be made, and you can't send any mail either, kupo!
        YOU_CAN_SEND_ITEMS_AND_GIL_TO_YOUR                                            = 7530,  -- You can send items and gil to your friends with the Send command, kupo!
        SOMETIMES_IF_A_SPECIAL_FORCE_TAKES_HOLD_YOU                                   = 7531,  -- (Sometimes, if a special force takes hold, you can even deliver items with the "Exclusive" attribute, kupo...!)
        CHANGING_PEOPLE_S_JOBS_IS_A_SECRET_ABILITY                                    = 7532,  -- Changing people's jobs is a secret ability only we moogles can use, kupo!
        I_TAKE_OFF_ALL_YOUR_EQUIPMENT_AND_TAKE                                        = 7533,  -- I take off all your equipment and take you to a mysterious place, kupo!
        AND_THE_REST_IS_A_SECRET_KUPO                                                 = 7534,  -- And...the rest is a secret, kupo!
        ALL_MOOGLES_LIKE_TAKING_CARE_OF_PLANTS_KUPO                                   = 7535,  -- All moogles like taking care of plants, kupo!
        AS_LONG_AS_YOU_HAVE_A_FLOWERPOT_AND                                           = 7536,  -- As long as you have a flowerpot and seeds, I'll make it my personal responsibility to look after the plants you raise, kupo!
        THIS_MOG_HOUSE_IS_YOUR_VERY_OWN_ROOM                                          = 7537,  -- This Mog House is your very own room, kupo! But it's still a little bare, kupo...
