        WELCOME_TO_THE_FRONTIER_THIS_STATION_HAS_ALREADY                              = 7859,  -- Welcome to the frontier! This station has already been built, but you can always help construct some bivouacs or keep them supplied.
        FRONTIER_STATIONS_ARE_SELF_SUFFICIENT_BUT_THE_BIVOUACS                        = 7860,  -- Frontier stations are self-sufficient, but the bivouacs are sadly not. We'd be extremely appreciative if you could undertake some assignments to make sure they stay in operation.
        HELLO_THERE_WE_HAVE_SOME_MATERIALS_WE_D                                       = 7861,  -- Hello, there! We have some materials we'd like delivered to town, but we have to go through the right channels. Would you mind undertaking a coalition assignment to transport them back?
        THANK_YOU_FOR_HELPING_US_OUT_HERE_S                                           = 7862,  -- Thank you for helping us out. Here's the %. All we ask is that you take it to the manager in charge of this assignment.
