        WELL_HERE_S_ANOTHER_BUT_PLEASE_BE_CAREFUL                                     = 7864,  -- Well, here's another %, but please be careful not to break this one.
        GOOD_DAY_TO_YOU_THIS_IS_FRONTIER_BIVOUAC                                      = 7865,  -- Good day to you. This is [the future site of /]frontier bivouac [#1/#2/#3/#4/#5].
        THANK_YOU_FOR_THE_WE_GREATLY_APPRECIATE_YOUR                                  = 7866,  -- Thank you for the %. We greatly appreciate your efforts to [help set up/provision] frontier bivouac [#1/#2/#3/#4/#5]. Please speak with the manager in charge of this assignment to collect your reward.
        I_M_TERRIBLY_SORRY_BUT_WE_CAN_T                                               = 7867,  -- I'm terribly sorry, but we can't use broken %. Could you please return to the coalition assignment desk and procure us another?
        HOW_NICE_IT_IS_TO_SEE_ANOTHER_FACE                                            = 7868,  -- How nice it is to see another face out here! As much as I'd like for you to help us set up frontier bivouac [#1/#2/#3/#4/#5], we won't be able to do anything until we've established a base of operations with a frontier station.
        THE_MAGICAL_PROPERTIES_OF_THE_WAYPOINT_PROVED_TOO                             = 7869,  -- The magical properties of the waypoint proved too much for your % to handle, and it broke...
        THIS_SEEMS_TO_BE_THE_SITE_OF_THE                                              = 7870,  -- This seems to be the site of the ergon locus oft called the [/Flourishing Island/Bud of the Swarm/Luminous Isle/Immutable Boulder/Immaculate Sands/Fruit of Fecundity/Dragon Driftwood/Torchbloom/Spring of Prosperity/Snowdrift Arbor/Frostbloom/Prominence of the Gales/Lake of Light/Sweltering Spring/Prominence of the Flame]. It is most likely worth surveying.
