        HI                                                                            = 8363,  -- %! Hi, %!
        YOU_RE_SHUCH_A_SHLOWPOKE_WE_VE_BEEN                                           = 8364,  -- You're shuch a shlowpoke. We've been waiting forever, tee hee.
        YEAH_ARSHIELA_WAS_REALLY_NISHE_AND_HELPED_ME                                  = 8365,  -- Yeah! Arshiela was really nishe and helped me find the perfect herbsh right away!
        SHE_SH_SHO_BRAVE_WE_KEPT_GOING_DEEPER                                         = 8366,  -- She'sh sho brave! We kept going deeper and deeper and deeper into the woodsh...
        AND_SHE_NEVER_GOT_SHCARED_OR_LOSHT_EVEN                                       = 8367,  -- And she never got shcared or losht even once, even though no one wash around!
        SHE_KNEW_A_LOT_ABOUT_ALL_THE_DIFFERENT                                        = 8368,  -- She knew a lot about all the different typesh of herbsh, too!
        NOT_JUSHT_THE_ONE_MY_GRAMPA_NEEDED_FOR                                        = 8369,  -- Not jusht the one my grampa needed for hish cough, but onesh that make you healthy and shtuff! She taught me a lotta new thingsh in that foresht.
        THEN_SHE_CASHT_SHOME_MAGIC_AND_WE_WENT                                        = 8370,  -- Then, she casht shome magic and we went Weeeeee all the way home really fasht!
        I_NEVER_KNEW_HOW_POWERFUL_MAGIC_COULD_BE                                      = 8371,  -- I never knew how powerful magic could be! Don't you think it'sh amashing too!?
        WHOOPSHIE_I_FORGOT_I_SHTILL_HAVE_TO_GIVE                                      = 8372,  -- Whoopshie! I forgot I shtill have to give my grampa hish medishine!
        THANKSH_FOR_RESHCUING_ME_FROM_THOSHE_EVIL_SHPIRITSH                           = 8373,  -- Thanksh for reshcuing me from thoshe evil shpiritsh, %! I thought I'd never make it back home!
        BYE_BYE                                                                       = 8374,  -- Bye-bye!
        WELL_WHAT_HAVE_WE_HERE_ANOTHER_NEWCOMER_TO                                    = 8375,  -- Well, what have we here? Another newcomer to Adoulin!
        BY_THE_LOOK_OF_YOU_I_D_SAY                                                    = 8376,  -- By the look of you, I'd say you're from the Middle Lands.
        DOES_THAT_ALSO_MEAN_YOU_RE_ONE_OF                                             = 8377,  -- Does that also mean you're one of those pioneers helping to colonize our continent?
        OH_I_TRULY_HOPE_YOU_ARE_HOW_INCREDIBLY                                        = 8378,  -- Oh, I truly hope you are! How incredibly grand it would be to see our daring and capable frontiersmen swell in rank! I can barely contain myself thinking about adding an extra member to our cause!
        EHEM_DESPITE_MY_OUTBURST_OF_ENTHUSIASM_THERE_I                                = 8379,  -- Ehem. Despite my outburst of enthusiasm there, I'm not actually part of the colonization movement. If you want to sign up and make Adoulin a safer, more habitable place, head on over to the Pioneers' Coalition and speak to Brenton.
        AS_THE_EIGHTH_CENTURY_CAME_TO_A_CLOSE                                         = 8380,  -- @@@As the eighth century came to a close, @@@so did the islands' old regime.
        THE_ROYAL_FAMILY_IN_PARTNERSHIP_WITH_THE_ELEVEN                               = 8381,  -- @@@The royal family, @@@in partnership with the eleven orders, @@@agreed to abolish imperial rule... @@@from which arose the Sacred City of Adoulin.
        THE_RATE_AT_WHICH_IT_DEVELOPED_ASTOUNDED_ALL                                  = 8382,  -- @@@The rate at which it developed astounded all. @@@In the blink of an eye, Adoulin had become @@@a maritime metropolis, its mercantile prowess @@@rivaling even that of Jeuno.
        THE_HUSTLE_AND_BUSTLE_OF_THE_COMMONERS_DISTRICT                               = 8383,  -- @@@The hustle and bustle of the commoners' district @@@in the west--Adoulin's center of trade and @@@pioneering hub--serves as a stark contrast @@@to the refined, stoic castle in the east.
        IT_IS_UPON_THIS_OPPIDAN_LANDSCAPE_THAT_ADVENTURERS                            = 8384,  -- @@@It is upon this oppidan landscape that @@@adventurers will first leave their mark @@@...in the next chapter of Vana'diel's @@@history.
        WELL_WELL_WELL_LOOKEE_WHAT_WE_VE_GOT                                          = 8385,  -- Well, well, well, lookee what we've got here. %? I reckon you must be an adventurer from those Middle Lands.
        THEN_LET_ME_BE_THE_FIRST_TO_WELCOME                                           = 8386,  -- Then let me be the first to welcome you to the splendiferous Sacred City of Adoulin, pardner!
        OH_I_AIN_T_YOUR_FIRST_I_FEEL                                                  = 8387,  -- Oh...I ain't your first...? I feel downright embarrassed! Although, ain't no one--especially %-carrying guy/gal] like yourself--gonna go on a stampede 'cause of a kind word!
        ENOUGH_SMALL_TALK_I_M_SURE_YOU_WANT                                           = 8388,  -- Enough small talk. I'm sure you want to get down to the nitty-gritty of the pioneer registration process right away.
        YOU_SAW_THE_BIG_OL_JUNGLE_TO_THE                                              = 8389,  -- You saw the big ol' jungle to the west of Jorius Yett, no? Bet you done seen nothin' like it!
        WELL_THAT_S_THE_AREA_WE_RE_TRYING                                             = 8390,  -- Well, that's the area we're trying to cultivate. Upon first glance it may look like she's ripe for the pluckin', but that old bird's got quite the temper on 'er!
        THAT_S_WHY_THAT_WHOPPER_OF_A_GATE                                             = 8391,  -- That's why that whopper of a gate was built long, long ago. After it went up, the number of casualties dropped faster than the first king's britches after a feast.
        JORIUS_YETT_ISN_T_THE_ONLY_SOURCE_OF                                          = 8392,  -- Jorius Yett isn't the only source of protection, though. We also issue % to pioneers so we can distinguish them from the layfolk.
        WITH_ONE_OF_THESE_HUMDINGERS_YOU_LL_BE                                        = 8393,  -- With one of these humdingers, you'll be able to undertake more jobs and receive more services around Adoulin than chocobos you can shake a stick at! ...Wait, that ain't very many...
        UGH_HOW_CAN_I_CHANGE_THE_SUBJECT_AHA                                          = 8394,  -- Ugh, how can I change the subject? Aha! I remember, I forgot to ask your name!
        IS_IT_WELL_IT_SEEMS_YOU_VE_PASSED                                             = 8395,  -- %, is it? Well, %, it seems you've passed our rigorous and discerning test! Here's your % to go along with your new pioneer status.
        JUST_DON_T_LOSE_IT_OR_THE_CONSEQUENCES                                        = 8396,  -- Just don't lose it, or the consequences will be dire. Dire, I say!
        OBTAINED_3                                                                    = 8397,  -- % obtained: %.
        HOW_S_IT_FEEL_TO_BE_ONE_OF                                                    = 8398,  -- How's it feel to be one of Adoulin's roughest and toughest? Great, right? Oooh, I'm so jealous!
        I_GUESS_I_LL_JUST_HAVE_TO_BE                                                  = 8399,  -- I guess I'll just have to be content with standing behind this here counter and informing true pioneers about all the tricks of the trade. I swear that's the only thing I'll ever do around here.
        THERE_S_NO_NEED_TO_LEARN_THEM_ALL                                             = 8400,  -- There's no need to learn them all at once, though. I know I'm a terrible chatterbox, but embarking upon a Vana'dielian Inquisition might make my jaw drop off.
        SO_WHAT_DO_YOU_WISH_TO_KNOW_HOMBRE                                            = 8401,  -- So, what do you wish to know, hombre/sweet thang]?
        WHAT_DO_YOU_WISH_TO_KNOW_ABOUT_THE                                            = 8402,  -- What do you wish to know about? The six coalitions. Coalition imprimaturs. Services and edification. Bayld. I've nothing to ask.
        THE_JUNGLE_STRETCHING_ITS_VIRID_TENDRILS_FROM_THIS                            = 8403,  -- The jungle stretching its virid tendrils from this here city out to the west is known by the disquieting name of...Eastern Ulbuka.
        I_KNOW_A_JUNGLE_BY_ANY_OTHER_NAME                                             = 8404,  -- I know, a jungle by any other name is still a jungle. However, we're asking you to take this overgrown deathtrap and turn it into a shining beacon of culture and civilization!
        THERE_RE_SIX_COALITIONS_THAT_LL_HAPPILY_ACCEPT                                = 8405,  -- There're six coalitions that'll happily accept the rough-'n-tumble of someone willing to get their hands dirty!
        LET_S_SEE_IF_I_CAN_GET_THEM                                                   = 8406,  -- Let's see if I can get them all on the first try... There's the Pioneers', the Couriers', the Inventors' Coalition...um...
        THE_SCOUTS_THE_PEACEKEEPERS_AND_THE_MUMMERS_COALITION                         = 8407,  -- ...the Scouts', the Peacekeepers', and the Mummers' Coalition.
        DID_I_GET_THEM_ALL_ONE_TWO_YEAH                                               = 8408,  -- Did I get them all? ...One...two...yeah, that's somewhere in the neighborhood of six.
        ANYWAY_GUESS_WHICH_OF_THESE_ROOTIN_TOOTIN_COALITIONS                          = 8409,  -- Anyway, guess which of these rootin' tootin' coalitions you're inside right now?
        DUHN_DUH_DUHHHN_THE_PIONEERS_COALITION_IT_S                                   = 8410,  -- Duhn-duh-duhhhn, the Pioneers' Coalition! It's a damn shame I can't dole out prizes for correct answers, but I will tell you that we do exactly what our name sounds like--burn the forces of nature that stand in our way to the ground with our pioneering spirit!
        NEXT_UP_IS_THE_COURIERS_COALITION_THEY_RE                                     = 8411,  -- Next up is the Couriers' Coalition. They're responsible for carrying provisions to frontier stations and frontier bivouacs...via dragons!
        IF_ONLY_THAT_WERE_TRUE_THEY_DO_TRANSPORT                                      = 8412,  -- If only that were true. They do transport vital resources, however, which must put a massive weight on their shoulders.
        AS_FOR_THE_INVENTORS_COALITION_THEY_DO_INDEED                                 = 8413,  -- As for the Inventors' Coalition, they do indeed make things, which run the gamut from tools of the trade to newfangled provisions. Their members are much smarter than me, that's for sure.
        THEN_THERE_S_THE_SCOUTS_COALITION_COMPOSED_OF                                 = 8414,  -- Then there's the Scouts' Coalition, composed of the most well-informed pioneers on the continent. They make their living by collecting and distributing information, as well as by conducting surveys and research regarding Eastern Ulbuka.
        WE_ALSO_HAVE_THE_FEW_THE_PROUD_THE                                            = 8415,  -- We also have the few, the proud, the Peacekeepers. Their coalition concerns itself with protecting the populace of this fair city and indulging in puff pastries while on duty.
        HAHAHA_BOY_DO_I_LOVE_A_GOOD_GUFFAW                                            = 8416,  -- Hahaha! Boy, do I love a good guffaw! In reality, though, they're a fit bunch. They have to be, too, 'cause the Peacekeepers' and Scouts' Coalitions are on the other side of Big Bridge in Eastern Adoulin.
        LAST_BUT_NOT_LEAST_WE_HAVE_THE_MUMMERS                                        = 8417,  -- Last but not least, we have the Mummers' Coalition. They're even bigger cards than me, I tell you what. Those rowdy roosters are in charge of managing facilities of fun and stress-relieving functions, which sets their coalition somewhat apart from the other five.
        WELL_THERE_YOU_HAVE_IT_WHEN_THE_POWERS                                        = 8418,  -- Well, there you have it. When the powers of these six coalitions combine, they captain each and every pioneer towards colonization success! Hopefully you'll find the one that's right for you.
        HERE_S_THE_LOWDOWN_THE_COALITIONS_HAND_OUT                                    = 8419,  -- Here's the lowdown. The coalitions hand out these slips we call imprimaturs to pioneers.
        TURNING_THEM_IN_AT_YOUR_LOCAL_COALITION_S                                     = 8420,  -- Turning them in at your local coalition's service counter gets you off on the right foot when undertaking jobs.
        THIS_SHOULD_GO_WITHOUT_SAYING_BUT_LET_ME                                      = 8421,  -- This should go without saying, but let me spell it out for all those bastards thinking about duping our kindly coalitions. Absolutely no work can be given to those who do not have an imprimatur.
        THEY_DON_T_HAVE_EXPIRATION_DATES_AND_THE                                      = 8422,  -- They don't have expiration dates, and the coalitions sure aren't going to run out of work anytime soon, so just keep an eye on your stock of them and you should be fine.
        YOU_CAN_T_CALL_THIS_THE_ERA_OF                                                = 8423,  -- You can't call this the era of the pioneer and not give them any work! That'd be like herding lucerewes with a spatula!
        WHAT_TYPE_OF_WORK_INDEED_WELL_I_VE                                            = 8424,  -- What type of work, indeed... Well, I've seen them offer everything from fetching random goods from seemingly unimportant people to listening to moronic misfits blather on about love. The possibilities are damn close to endless.
        NO_MATTER_WHAT_THE_TASK_THOUGH_A_TRUE                                         = 8425,  -- No matter what the task, though, a true pioneer and coalition member will perform his/her] duty with glee, for it can always conceivably help the colonization effort.
        SPEAKING_OF_HELP_I_BIT_OFF_A_TAD                                              = 8426,  -- Speaking of help, I bit off a tad more than I could chew at the auction house the other day...
        WHAT_AM_I_THINKING_I_SHOULD_JUST_GET                                          = 8427,  -- What am I thinking!? I should just get the Scouts' Coalition to dig up some dirt on the head of the auction house instead, heh heh heh...
        WHOOPSIE_DAISY_WHERE_WAS_I_AGAIN                                              = 8428,  -- Whoopsie daisy, where was I again?
        OH_YES_COALITION_IMPRIMATURS_I_KNOW_I_KNOW                                    = 8429,  -- Oh, yes. Coalition imprimaturs. I know, I know, I know. You're thinking, Why do they gotta keep us chained to a post like that? You ain't the only one complaining about it.
        THE_THING_IS_THAT_THE_COALITIONS_OPERATE_OFF                                  = 8430,  -- The thing is that the coalitions operate off capital they receive from the city, which not only funds the operation and upkeep of facilities, but also pays for pioneer compensation...
        AND_OF_COURSE_WE_ALL_KNOW_THAT_NEITHER                                        = 8431,  -- And of course, we all know that neither bayld nor gil grow on goobbues.
        AFTER_THE_CIVIC_BIGWIGS_DECIDED_TO_RECRUIT_YOU                                = 8432,  -- After the civic bigwigs decided to recruit you Middle Lands adventurers in droves, they realized they also needed a plan to corral the caravans of cash that would undoubtedly need to be paid out. You understand how shortsighted politicians are, I'm sure.
        THE_LONG_AND_THE_SHORT_OF_IT_IS                                               = 8433,  -- The long and the short of it is that without some way to bail us out, this place would capsize faster'n a dinghy in a tempest!
        WORD_IS_THAT_THE_WHOLE_SYSTEM_IS_UNDER                                        = 8434,  -- Word is that the whole system is under review by a minister of commerce-appointed subcommittee, though, so it's possible that they'll scrap the whole kit and caboodle if we rope ourselves a big'un with this pioneering project.
        YET_MORE_JARGON_COMING_UP_MY_BUSHWHACKING_BRIGAND                             = 8435,  -- Yet more jargon coming up, my bushwhacking brigand. Each coalition has its own support system for pioneers.
        THIS_CANOPY_OF_SERVICES_GROWS_LUSHER_AND_STURDIER                             = 8436,  -- This canopy of services grows lusher and sturdier the more money your coalition receives.
        AS_I_M_SURE_YOU_VE_ALREADY_FIGURED                                            = 8437,  -- As I'm sure you've already figured out, the way to raise this metaphorical canopy is by razing real ones! Contribute to the colonization of Adoulin, get funds for your coalition, and watch it sprout before your very eyes!
        WHAT_EXACTLY_DOES_THIS_ENTAIL_FOR_ITS_MEMBERS                                 = 8438,  -- What exactly does this entail for its members, you ask?
        THE_BIGGER_A_COALITION_GROWS_THE_BETTER_ITS                                   = 8439,  -- The bigger a coalition grows, the better its services become, the more lavish your headquarters will look, and the faster you'll be able to colonize the wilderness.
        THE_MORE_EFFICIENTLY_YOU_PIONEERS_WORK_THE_FASTER                             = 8440,  -- The more efficiently you pioneers work, the faster you'll be able to contribute to the coalition, and so the cycle repeats. In summation, helping the coalition is like helping yourself!
        OH_YOU_WANT_A_NAME_FOR_THIS_PROCESS                                           = 8441,  -- Oh, you want a name for this process as well? Punny you should ask, for some clever chap named it edification. Anyway, I hope you find a damn good coalition and make them proud!
        AFTER_THE_SECRETS_OF_THAT_UBIQUITOUS_SILT_THAT                                = 8442,  -- After the secrets of that ubiquitous silt that's verdant as a handful of moss, are we?
        FOR_STARTERS_IT_S_ONE_OF_OUR_MOST                                             = 8443,  -- For starters, it's one of our most cherished natural resources. Truly a sight to behold. If you've ever laid eyes on it, I'm sure you'll agree.
        BUT_ITS_BEAUTY_ISN_T_THE_ONLY_REASON                                          = 8444,  -- But its beauty isn't the only reason it's adored all over the continent. We also trade with it. Fine-grained granules may sound like a half-baked currency, but pioneers seem happy enough when they get paid in it or find it in Eastern Ulbuka.
        I_KNOW_I_KNOW_WHY_NOT_GIL_INSTEAD                                             = 8445,  -- I know, I know. Why not gil instead? Maybe it's a cultural thing, but bayld is all the rage in these pastures. Without it, you can't do squat here.
        I_GUESS_THAT_DOES_IT_FOR_MY_BAYLD                                             = 8446,  -- I guess that does it for my bayld explanation. There's probably more to say, but I don't feel much like saying it.
        I_FIND_IT_BEST_NOT_TO_TROUBLE_MY                                              = 8447,  -- I find it best not to trouble my ol' noggin too much about particulars. Try living by the mantra of Be it gem or phlegm, just take 'em! when you're in the field, and everything should work out fine.
        I_SEE_HOW_IT_IS_DON_T_WANT                                                    = 8448,  -- I see how it is. Don't want to hear babbling Brenton talk, do you?
        HAVE_BRENTON_STOP_BABBLING_WAIT_I_MUST_KNOW                                   = 8449,  -- Have Brenton stop babbling? Wait, I must know something! Yes, and how!
        DO_YOU_NOW_WHAT_IS_IT_PARDNER                                                 = 8450,  -- Do you now? What is it, pardner?
        I_UNDERSTAND                                                                  = 8451,  -- I understand...
        I_STILL_LIKE_YOUR_FACE_THOUGH_HERE_TAKE                                       = 8452,  -- I still like your face, though. Here, take this bayld as a symbol of your new life as a pioneer.
        WHEN_YOU_FINALLY_DECIDE_TO_LEAVE_ADOULIN_PRESENT                              = 8453,  -- When you finally decide to leave Adoulin, present that to a guard and they'll slap Ionis on you.
        IT_DEPENDS_ON_HOW_MUCH_EDIFICATION_THE_VARIOUS                                = 8454,  -- It depends on how much edification the various coalitions have undergone, but Ionis should bestow different powers upon you, making your destiny seem almost manifest!
        NOW_GO_OUT_THERE_AND_MAKE_ME_PROUD                                            = 8455,  -- Now go out there and make me proud like the son/daughter] I never had! I'm quaking with delight just thinking of all the amazing stories I'll be able to tell the guys down at the tavern!
        WHAT_TIMING                                                                   = 8456,  -- What timing, %!
        YOU_VE_BEEN_INVITED_TO_DINE_WITH_THE                                          = 8457,  -- You've been invited to dine with the members of Adoulin's cabinet!
        I_M_GONNA_FEED_OFF_THIS_ACCOMPLISHMENT_OF                                     = 8458,  -- I'm gonna feed off this accomplishment of yours vicariously for weeks!
        AS_REAL_AS_THE_DICKENS_THOUGH_I_COULDN                                        = 8459,  -- As real as the dickens, though, I couldn't be happier for you, %. Take this as a token of my appreciation.
        ONCE_YOUR_BISON_STOPS_BUCKIN_PUT_ON_YOUR                                      = 8460,  -- Once your bison stops buckin', put on your best bib and tucker and get yourself over to Adoulin Castle.
        BY_THE_WAY_SCUTTLEBUTT_AROUND_THE_BARNYARD_IS                                 = 8461,  -- By the way, scuttlebutt around the barnyard is that you've performed some truly courageous feats, %...
        SUCH_AS_FELLING_WHO_WATCHES_OVER                                              = 8462,  -- Such as felling [Colkhab, the Matriarch Naakual/Tchakka, the Riptide Naakual/Achuka, the Firebrand Naakual/Yumcax, the Ligneous Naakual/Hurkan, the Booming Naakual/Kumhau, the Flashfrost Naakual], who watches over [Ceizak Battlegrounds/Foret de Hennetiel/Morimar Basalt Fields/Yorcia Weald/Marjami Ravine/Kamihr Drifts]!
        I_CAN_HARDLY_BELIEVE_THERE_WAS_A_TIME                                         = 8463,  -- I can hardly believe there was a time when I had to teach you the ropes! It seems like we just met yesterday, yet you've already defeated # Naakual[/s]! While we Adoulinians sit quaking in our chaps, you're out whooping 'em good!
        MAYBE_THIS_IS_ALL_IN_A_DAY_S                                                  = 8464,  -- Maybe this is all in a day's work for you adventurers? I guess you've been lassoing Vana'diel's wildest afore the first bison drive.
        TRAVELERS_VE_TOLD_MANY_A_TALL_TALE_ABOUT                                      = 8465,  -- Travelers've told many a tall tale about your exploits. I guess they weren't so tall after all...
        COME_TO_THINK_OF_IT_HAVE_YOU_EVER                                             = 8466,  -- Come to think of it, %, have you ever heard of the Naakuals?
        THEY_RE_THE_RANCHERS_OF_THE_CONTINENT_S                                       = 8467,  -- They're the ranchers of the continent's frontier, and more temperamental than a bull in heat.
        RUMORS_ABOUND_THAT_THE_NAAKUALS_KEEP_THWARTING_THE                            = 8468,  -- Rumors abound that the Naakuals keep thwarting the pioneers' best efforts thanks to some puppeteer or whatnot, but I've yet to see any proof in that pudding.
        EITHER_WAY_IT_SEEMS_THEIR_TRAILS_AND_OURS                                     = 8469,  -- Either way, it seems their trails and ours are bound to cross.
        YOU_MIGHT_AS_WELL_LEARN_EM_A_THING                                            = 8470,  -- You might as well learn 'em a thing or two while you're moseying about the jungle.
        TELL_EM_TO_PONY_UP_AND_GET_IN                                                 = 8471,  -- Tell 'em to pony up and get in line like the rest of the herd so you pioneers can lead Ulbuka to greatness!
        NAAKUALS_START_OF_THE_EVENT_HAVEN_T_BEAT                                      = 8472,  -- Naakuals Start of the event. Haven't beat any. The Matriarch Naakual. The Riptide Naakual. The Ligneous Naakual. The Firebrand Naakual. The Booming Naakual. The Flashfrost Naakual.
        YOU_ALREADY_ADJUSTED_TO_LIFE_ON_THE_GOOD                                      = 8473,  -- You already adjusted to life on the good ol' Adoulin ranch? Hope so, because we're lookin' for you to wrangle us some big'uns, sonny/missy].
        HEY_IT_S_LISTEN_I_VE_GOT_SOMETHING                                            = 8474,  -- Hey--it's %! Listen, I've got something juicy for you, though you may have heard already... ...It's about the leafkin.
        YOU_MIGHT_VE_SEEN_STREET_VENDORS_SELLING_POCKET                               = 8475,  -- You might've seen street vendors selling pocket-sized leafkin charms. Their popularity is simply beyond compare.
        THE_SUPERSTITIONS_SOME_PEOPLE_WILL_CLING_TO_BUT                               = 8476,  -- The superstitions some people will cling to... But that's neither here nor there. I bring you some interesting gossip--I've heard that they have a gathering spot of sorts in Yorcia Weald. Have you ever been there?
        HAVE_YOU_BEEN_TO_THERE_YES_WHAT_A                                             = 8477,  -- Have you been to there? Yes. What a sight to behold. No. But it sounds interesting...
        YOU_HAVE_ALL_THE_BETTER                                                       = 8478,  -- You have! All the better.
        THERE_ARE_WHISPERS_GOING_AROUND_ABOUT_A_REGAL                                 = 8479,  -- There are whispers going around about a regal matriarch who rules over them all. Are you familiar with the story?
        DO_YOU_KNOW_OF_THEIR_QUEEN_OF_COURSE                                          = 8480,  -- Do you know of their queen? Of course. What a story! Umm...does she have a crown?
        YOUR_KNOWLEDGE_REALLY_HAS_NO_BOUNDS                                           = 8481,  -- %, your knowledge really has no bounds!
        THEY_RE_ONLY_RUMORS_HOW_AM_I_SUPPOSED                                         = 8482,  -- They're only rumors, %! How am I supposed to know? If she really does exist, though, she must have some wonderful stories to tell.
        THEN_YOUR_FIRST_GOAL_IS_TO_FIND_WHERE                                         = 8483,  -- Then your first goal is to find where they live. There's something I'd like you to do for me when you arrive.
        YOU_MUST_BE_AWARE_OF_RECENT_ABNORMALITIES_IN                                  = 8484,  -- You must be aware of recent...abnormalities in the forest, being a pioneer and all.
        THOSE_LEAFKIN_BUGGERS_ARE_DEEPLY_INTERTWINED_WITH_NATURE                      = 8485,  -- Those leafkin buggers are deeply intertwined with nature, so they could assist in getting to the root of the problem. Haha. Root. I kill me.
        THE_PROBLEM_IS_THAT_NONE_OF_THEM_SPEAK                                        = 8486,  -- The problem is that none of them speak the common tongue...none, that is, except for the queen. I mean, if monarchs are supposedly deities incarnate, I'd certainly expect them to have a leg up on their followers.
        YOU_RE_GONNA_MAKE_ME_SPELL_IT_OUT                                             = 8487,  -- You're gonna make me spell it out, aren't you?
        I_WANT_YOU_TO_FIND_AND_APPROACH_THE                                           = 8488,  -- I want you to find and approach the queen and then seek her advice.
        WE_NEED_TO_LEARN_MORE_ABOUT_WHAT_S                                            = 8489,  -- We need to learn more about what's wrong with the forest. The rivers are running dry, the flora is changing at a dizzying rate...and worse.
        SOME_HAVE_EVEN_REPORTED_HEARING_UNNATURALLY_FERAL_SCREAMS                     = 8490,  -- Some have even reported hearing unnaturally feral screams thundering across the land. Such an ill portent for our pioneering activities.
        NONE_TO_DATE_HAVE_SUCCEEDED_IN_MEETING_HER                                    = 8491,  -- None to date have succeeded in meeting her, though not for lack of trying.
        IF_SHE_EXISTS_SHE_CERTAINLY_WOULDN_T_TRUST                                    = 8492,  -- If she exists, she certainly wouldn't trust us. There must be some way we can open her heart, though the details escape me.
        IF_IT_WERE_A_MERE_QUESTION_OF_WORDS                                           = 8493,  -- If it were a mere question of words, then we would just send a city envoy to parlay with her. No, it's got to be something more material.
        TO_MEET_WITH_THE_QUEEN_YOU_LL_HAVE                                            = 8494,  -- To meet with the queen, you'll have to earn the trust of her tribe. I wish I could offer you more clues, but those are all the hints I can give you.
        SO_WHAT_DO_YOU_SAY_FEELING_UP_TO                                              = 8495,  -- So what do you say? Feeling up to the challenge?
        FIND_THE_LEAFKIN_QUEEN_YES_WHAT_AN_ADVENTURE                                  = 8496,  -- Find the leafkin queen? Yes. What an adventure! Leaves scare me.
        OUTSTANDING_ADOULIN_IS_COUNTING_ON_YOU                                        = 8497,  -- Outstanding! Adoulin is counting on you, %!
        THAT_S_A_DAMN_SHAME_I_D_ADVISE                                                = 8498,  -- That's a damn shame. I'd advise you to think about what this could mean for the city and come back to me once you've changed your mind.
        HOW_ABOUT_IT_HAVE_YOU_RETHOUGHT_MY_PROPOSITION                                = 8499,  -- How about it, %? Have you rethought my proposition of finding the leafkin queen?
        WE_NEED_INFORMATION_MORE_THAN_ANYTHING_ELSE_NO                                = 8500,  -- We need information more than anything else--no use going in blind. You might be able to find out something at the Mummers' Coalition, what with all the pioneers coming and going.
        NOT_LIKE_I_CAN_SAY_FOR_SURE                                                   = 8501,  -- (Not like I can say for sure...)
        HMM_OH_PAY_MY_RAMBLINGS_NO_HEED_GODDESSSPEED                                  = 8502,  -- Hmm? Oh, pay my ramblings no heed. Goddessspeed, %!
        WHY_SUCH_A_SOUR_LOOK_ON_YOUR_FACE                                             = 8503,  -- %! Why such a sour look on your face?
        IT_IS_WHOLLY_UNBECOMING_BUT_PLEASE_I_AM                                       = 8504,  -- It is wholly unbecoming. But please, I am more than willing to lend an ear if it would help absolve you of your worries. I have got all the time in the world, after all.
        SO_TELL_ME_WHAT_TROUBLES_YOU_THIS_FINE                                        = 8505,  -- So tell me--what troubles you this fine day?
        WHAT_WOULD_YOU_LIKE_TO_DISCUSS_MEETING_THE                                    = 8506,  -- What would you like to discuss? Meeting the leafkin queen.
        AH_YES_HER_ROYAL_HIGHNESS_IF_YOU_WILL                                         = 8507,  -- Ah, yes. Her Royal Highness, if you will. Should you have the time, I would enjoy nothing more than to regale you with some relevant tales of old.
        BUT_BEFORE_I_DO_HAVE_YOU_HAD_THE                                              = 8508,  -- But before I do... Have you had the fortune--or perhaps misfortune--of tussling with one of the Naakuals?
        EXCELLENT_YOUR_SKILL_MATCHES_YOUR_TOUGH_DEMEANOR_I                            = 8509,  -- Excellent. Your skill matches your tough demeanor. I should expect nothing less from one who has crossed swords with them.
        I_AM_CERTAIN_YOU_HAVE_AT_LEAST_HEARD                                          = 8510,  -- I am certain you have at least heard of their existence.
        GUARDIANS_OF_ULBUKA_HER_WRATH_MADE_MANIFEST_IF                                = 8511,  -- Guardians of Ulbuka--her wrath made manifest. If you wish to progress into the wilds, locking horns is inevitable.
        BE_THAT_AS_IT_MAY_I_PROMISED_YOU                                              = 8512,  -- Be that as it may, I promised you a story, and a story you shall have. Having spent many days and nights in Adoulin, you have surely heard the name of the founder king spoken by noble and peasant alike.
        THE_TRIALS_AND_TRIBULATIONS_OF_CENTURIES_PAST_ARE                             = 8513,  -- The trials and tribulations of centuries past are naught but legends to people living today. This story involves one of these legends.
        THE_FOOLHARDY_KING_VENTURED_INTO_THE_WILDS_WITH                               = 8514,  -- The foolhardy king ventured into the wilds with his entourage, invading the lands of Ulbuka and slaughtering all foes in his path.
        THOUGH_HIS_BLADE_SLICED_THROUGH_THE_FLESH_OF                                  = 8515,  -- Though his blade sliced through the flesh of many like strands of silk, a few particularly lurid beasts--those that now serve as keepers of the wilds--were not to be tamed so easily. When they were at last bested, they swore fealty to the founder king.
        TODAY_WE_REFER_TO_THEM_AS_THE_NAAKUALS                                        = 8516,  -- Today, we refer to them as the Naakuals.
        HE_SUBJUGATED_ONE_RACE_AFTER_ANOTHER_EVENTUALLY_BREACHING                     = 8517,  -- He subjugated one race after another, eventually breaching the sanctity of the forest's most inner recesses.
        YET_SOMETHING_CAUSED_HIM_TO_ABANDON_HIS_GOAL                                  = 8518,  -- Yet something caused him to abandon his goal of colonization.
        YEARS_LATER_HE_LEFT_THE_FOLLOWING_WORDS_AS                                    = 8519,  -- Years later, he left the following words as he lay on his deathbed: Never again must man tread upon the land of Ulbuka.
        THIS_EPITHET_HAS_BEEN_KNOWN_THROUGHOUT_ADOULIN_S                              = 8520,  -- This epithet has been known throughout Adoulin's history as the Ancient Pact.
        THE_NAAKUALS_ARE_BOUND_BY_THIS_VERY_PACT                                      = 8521,  -- The Naakuals are bound by this very pact--but they are not the only ones. Do you see where I am heading?
        WELL_DO_YOU_SO_YOU_MEAN_THE_LEAFKIN                                           = 8522,  -- Well, do you? So you mean the leafkin...?
        PRECISELY                                                                     = 8523,  -- Precisely!
        YOU_SEE_THE_LEAFKIN_DO_NOT_LOOK_KINDLY                                        = 8524,  -- You see, %, the leafkin do not look kindly on mankind's encroachment upon Ulbuka, as it violates the word and spirit of the sacred deal they made with the founder king. Its power is absolute.
        THE_ONLY_ONE_WHO_CAN_NULLIFY_THE_PACT                                         = 8525,  -- The only one who can nullify the pact would be the founder king himself...or one of his bloodline.
        IT_WAS_NOT_COMPARATIVELY_LONG_AGO_THAT_MAN                                    = 8526,  -- It was not comparatively long ago that man respected this code to the same degree as the denizens of the forest... When the Order of Adoulin was a royal force superceding all, that is.
        HIS_DYING_WISHES_WERE_ALSO_ENGRAVED_UPON_THE                                  = 8527,  -- His dying wishes were also engraved upon the sword that he once carried at his side.
        THROUGHOUT_THE_CENTURIES_EACH_KING_OF_ADOULIN_HAD                             = 8528,  -- Throughout the centuries, each king of Adoulin had held the sword high in front of his subjects, swearing to uphold his ancestor's grand promise.
        YOUR_EYES_WIDEN_IN_SURPRISE_I_ASSURE_YOU                                      = 8529,  -- Your eyes widen in surprise. I assure you, every last syllable is steeped in truth.
        THROUGHOUT_ALL_OF_ADOULIN_S_HISTORY_HER_CITIZENS                              = 8530,  -- Throughout all of Adoulin's history, her citizens only set foot in Ulbuka on two occasions.
        THE_FIRST_OF_COURSE_WAS_WHEN_THE_FOUNDER                                      = 8531,  -- The first, of course, was when the founder king himself treaded upon the land. The second was in an age called the Great Expedition, a time when the founder king's words had begun to fade from memory.
        THE_REMNANTS_OF_THE_ENCAMPMENTS_SET_UP_DURING                                 = 8532,  -- The remnants of the encampments set up during that time still exist to this day on the shoreline of the eastern sea.
        FORGIVE_ME_MY_STORY_HAS_VEERED_OFF_IN                                         = 8533,  -- Forgive me--my story has veered off in an unexpected direction. As I was explaining, throughout time, Adoulin's rulers have always respected the pact.
        WHENEVER_A_NEW_KING_ASCENDED_HE_WOULD_TAKE                                    = 8534,  -- Whenever a new king ascended, he would take hold of the sword and swear a solemn oath to uphold that which had been passed down through the ages.
        YET_WINDS_OF_CHANGE_STARTED_TO_SWEEP_THE                                      = 8535,  -- Yet winds of change started to sweep the city, and the Order of Adoulin was reorganized into one of twelve noble houses.
        WHEN_YGNAS_THE_CURRENT_LEADER_OF_THE_ORDER                                    = 8536,  -- When Ygnas, the current leader of the Order of Adoulin, came to power, he was just one man in charge of his house--his influence over the city muted at best.
        HE_CHOSE_TO_ABANDON_THE_SWORD_DECLARING_THAT                                  = 8537,  -- He chose to abandon the sword, declaring that the colonization of Ulbuka was to recommence--a stance not taken in well more than two dozen generations.
        THUS_A_NEW_AGE_DAWNED_UPON_THE_CITY                                           = 8538,  -- Thus, a new age dawned upon the city--one of pioneering and progress.
        SO_IF_HE_FORESOOK_THE_BLADE_OF_HIS                                            = 8539,  -- So if he foresook the blade of his forefathers, into whose hands did it fall?
        THINK_HARD_DEAR_THE_ONE_WHO_POSSESSES_IT                                      = 8540,  -- Think hard, dear %. The one who possesses it is the one closest to Ygnas himself--one present at his coronation.
        IN_FACT_YOU_HAVE_LAID_EYES_UPON_THE                                           = 8541,  -- In fact, you have laid eyes upon the blade on more than one occasion.
        WHO_IS_THE_BEARER_OF_THE_BLADE_IT                                             = 8542,  -- Who is the bearer of the blade? It must be Arciela!
        THE_SWORD_THAT_OUR_PRINCESS_NOW_WIELDS_IS                                     = 8543,  -- The sword that our princess now wields is the only thing that represents the will of the founder king himself.
        I_PROFESS_THAT_I_HAVE_A_TENDENCY_TO                                           = 8544,  -- I profess that I have a tendency to ramble, but I assume this tale served to scatter the clouds of doubt that were surely muddling your thoughts.
        THINK_OF_IT_AS_A_TIDBIT_OF_WISDOM                                             = 8545,  -- Think of it as a tidbit of wisdom from someone with idle hands and tongue.
        AT_MY_AGE_DREAMS_ARE_A_THING_OF                                               = 8546,  -- At my age, dreams are a thing of the past...as they have been for decades upon decades.
        SOMETIMES_I_CATCH_MYSELF_THINKING_ABOUT_THE_FOUNDER                           = 8547,  -- Sometimes I catch myself thinking about the founder king. All he wanted was to catch dreams in his hands.
        AND_SO_HE_REACHED_OUT_INTO_THE_DEPTHS                                         = 8548,  -- And so he reached out into the depths of the forest, attempting to seize what no man had ever touched.
        AT_LEAST_SO_GO_THE_STORIES_THAT_THEY                                          = 8549,  -- At least, so go the stories that they tell.
        YOU_ADVENTURERS_CLING_TO_YOUR_DESIRES_IN_MUCH                                 = 8550,  -- You adventurers cling to your desires in much the same way. No. Forget what I just told you and leave me to my wanderings.
        HEY_WELCOME_BACK_DID_YOU_MANAGE_TO_FIND                                       = 8551,  -- Hey, welcome back! Did you manage to find out anything?
        THE_FOUNDER_KING_S_SWORD_OH_YOU_MEAN                                          = 8552,  -- The founder king's sword? Oh, you mean the one that Princess Arciela always keeps at her side.
        YOU_KNOW_HOW_IT_HAPPENED_TO_COME_INTO                                         = 8553,  -- You know how it happened to come into her possession? Ygnas bequeathed it to her when he ascended to his current station.
        TO_THINK_THAT_SUCH_A_BLADE_WOULD_BE                                           = 8554,  -- To think that such a blade would be a relic of centuries past...
        SHE_GUARDS_IT_LIKE_A_PROTECTIVE_MOTHER_WOULD                                  = 8555,  -- She guards it like a protective mother would guard her son. Never once has anyone seen her without it.
        YOU_WANT_TO_BORROW_IT_ARE_YOU_OUT                                             = 8556,  -- You want to borrow it!? Are you out of your mind?
        IT_MUST_BE_REALLY_IMPORTANT_FOR_YOU_TO                                        = 8557,  -- It must be really important for you to say something so brash.
        OH_HO_SO_THAT_S_THE_RUB_YOU                                                   = 8558,  -- Oh ho, so that's the rub--you think the leafkin will trust you if you have that sword.
        NOT_THAT_I_EXPECT_HER_TO_GIVE_IT                                              = 8559,  -- Not that I expect her to give it up like some piece of hard candy, but if you want to try, you can find the princess in Castle Adoulin.
        SURE_IT_MIGHT_BE_LIKE_WRINGING_BLOOD_FROM                                     = 8560,  -- Sure, it might be like wringing blood from a stone, but it's at least worth a shot! It's the only way to figure out what's going wrong with the land!
        SO_HEY_THERE_VE_BEEN_RUMORS_YOU_WERE                                          = 8561,  -- So, hey...there've been rumors you were spotted together with Arciela in the jungle. (For Altana's sake, didn't I tell him/her] to find Arciela at the castle, not by traipsing about Ulbuka?)
        WELL_THAT_LL_TEACH_ME_TO_GO_STICKING                                          = 8562,  -- Well, that'll teach me to go sticking my nose into things. Just go along with your business.
        MUMBLE_MURMUR_THIS_AIN_T_IT_NEITHER                                           = 8563,  -- <Mumble> <murmur> This ain't it, neither...
        WHAT_M_I_DOIN_JUST_PININ_FOR_TH                                               = 8564,  -- What'm I doin'? Just pinin' for th' days of old, I tell you what.
        IT_S_ALL_CAUSE_OF_SOMETHIN_THAT_DONE                                          = 8565,  -- It's all 'cause of somethin' that done happened three score years afore. An adventurer from the Middle Lands--much like yourself/...'cept he was a guy]--let me partake of the mightiest-tasting bev'rage that's ever tickled my tongue.
        THE_FRUIT_IT_WAS_SQUEEZED_FROM_HAD_MORE                                       = 8566,  -- The fruit it was squeezed from had more bumps and blemishes than an octogenarian, and its snot-green color didn't make it look any more appealing. Its innards, however, they was the most molten shade of passionate red I've ever done seen. If it'd had blood, it would've been boiling.
        BUT_THE_FLAVOR_S_WHAT_REALLY_DID_YA                                           = 8567,  -- But the flavor's what really did ya in. Sweet like your first kiss, and sour like the moment her daddy caught ya.
        IT_WENT_DOWN_SMOOTH_TOO_SMOOTHER_N_A                                          = 8568,  -- It went down smooth, too. Smoother'n a used chocobo salesman, but wit' none o' th' grease.
        SIXTY_YEARS_LATER_THOUGH_AND_I_M_ON                                           = 8569,  -- Sixty years later, though, and I'm on my deathbed.
        AIN_T_GOT_NO_WIFE_NO_MORE_NEVER                                               = 8570,  -- Ain't got no wife no more, never wanted no dirty kids, and my best years are so far behind me that they've fallen and can't get up. All I've got left to comfort me now is the unforgettable taste of that drink.
        NOTHIN_S_EVER_MADE_ME_FEEL_SO_ALIVE                                           = 8571,  -- Nothin's ever made me feel so alive, so...satisfied.
        IF_ONLY_I_D_HAD_THE_WHEREWITHAL_TO                                            = 8572,  -- If only I'd had the wherewithal to ask what the name of that fruit was...
        WAIT_A_DADGUM_MINUTE_AS_AN_ADVENTURER_YOU                                     = 8573,  -- Wait a dadgum minute. As an adventurer, you ain't just been to the Middle Lands, but all differ'nt parts o' Vana'diel, right?
        IF_YOU_EVER_GET_YOUR_HANDS_ON_ONE                                             = 8574,  -- If you ever get your hands on one and pass it thisaway, I'd die a happy man.
        LET_THE_MAN_DIE_HAPPY_SURE_I_LL                                               = 8575,  -- Let the man die happy? Sure, I'll search for it. If I can't be happy, no one can.
        ITS_PEEL_S_ALL_LUMPY_AND_GREEN_TO                                             = 8576,  -- Its peel's all lumpy and green to the point of inducing vomit, but the fruit itself's as heartwarmingly red as my wife of forty years was...<sob>.
        SNIFF_ANYWAY_MY_LIFE_S_SO_SAD_THAT                                            = 8577,  -- <Sniff> Anyway, my life's so sad that a fruit's the best thing in it. Please, bring me this one bit o' joy.
        FINE_I_KNOW_WHO_D_WANT_TO_HELP                                                = 8578,  -- ...Fine. I know, who'd want to help a man so old that he probably dreamed up the whole fruit bev'rage memory anyway. Ugh, life...
        JUST_THE_MEMORY_OF_THAT_DRINK_S_SUBLIME                                       = 8579,  -- Just the memory of that drink's sublime flavor comforts me in the wee hours of the night while I'm up regrettin' the choices I've made.
        I_DO_NOT_BELIEVE_WE_HAVE_MET_BEFORE                                           = 8580,  -- I do not believe we have met before. My name is Teodor.
        AND_YOU_ARE                                                                   = 8581,  -- And you are...?
        IS_IT                                                                         = 8582,  -- %, is it?
        THAT_NAME_IS_CERTAINLY_A_RARITY_ON_THIS                                       = 8583,  -- That name is certainly a rarity on this continent. I take it you were born on the other side of the sea?
        HMMM_AN_ADVENTURER_FROM_THE_MIDDLE_LANDS_COME                                 = 8584,  -- Hmmm... An adventurer from the Middle Lands, come to assist in the colonization movement. How altruistic.
        I_CANNOT_EXPRESS_HOW_COMFORTING_IT_IS_TO                                      = 8585,  -- I cannot express how comforting it is to lay eyes on your visage once more, %.
        HAVE_YOU_BEEN_ENJOYING_YOUR_LITTLE_ROMP_THROUGH                               = 8586,  -- Have you been enjoying your little romp through the wilderness of fair Ulbuka? It simply would not do for you to come all the way here and not indulge in what we have to offer. Life is long and terribly dull, so you must seize any opportunities to appreciate it when they present themselves.
        THE_ONLY_ISSUE_IS_THAT_NO_MATTER_HOW                                          = 8587,  -- The only issue is that no matter how interesting the diversions, they rarely stand the test of time. That is why novelty matters the most in such affairs.
        THIS_METAPHORICAL_FRESHNESS_PRESERVES_NOT_ONLY_ONE_S                          = 8588,  -- This metaphorical freshness preserves not only one's sanity, but his youth as well. Of the mind, that is. That of the body is an entirely separate matter.
        I_SEE_THAT_THIS_DRINK_IN_MY_HAND                                              = 8589,  -- I see that this drink in my hand does a far better job at holding your attention than my dusty old words. It is a concoction made with the juice of a certain fruit that grows deep within the Ulbukan jungle.
        I_PROFESS_THAT_IT_IS_ONE_OF_MY                                                = 8590,  -- I profess that it is one of my favorite beverages, but alas, the fruit that gives birth to it is rare and highly unobtainable.
        SIMPLY_LOOK_AT_THIS_RUDDY_HUE_THAT_MIMICS                                     = 8591,  -- Simply look at this ruddy hue that mimics a bleeding sunset. And the piquant aroma that delicately tickles one's nose.
        I_CAN_HARDLY_PICTURE_THE_LOOK_OF_SHOCK                                        = 8592,  -- I can hardly picture the look of shock that must have crossed the face of the person who first discovered it, seeing how its outward appearance resembles a ball of hardened phlegm hocked carelessly onto the ground by a terminally ill old man.
        SOURCES_DO_TELL_ME_THAT_PIONEERS_HAVE_BEEN                                    = 8593,  -- Sources do tell me that pioneers have been making a habit of bringing some back with them, but the fruit rarely makes it to conventional mercantile channels, as this shopkeep tells me his stocks are bone-dry.
        HAVE_YOU_SUCCUMBED_TO_THE_TEMPTATIONS_OF_THIS                                 = 8594,  -- Have you succumbed to the temptations of this luscious fruit as well, my dear %?
        THEN_I_SUGGEST_PAYING_A_VISIT_TO_THE                                          = 8595,  -- Then I suggest paying a visit to the Couriers' Coalition, as it is they who keep watch over the innumerable goods that make their way into and out of this nation.
        I_ASSUME_YOU_WISH_TO_TREK_THERE_WITH                                          = 8596,  -- I assume you wish to trek there with utmost haste, and therefore will refrain from keeping you much longer.
        YOU_DID_NOT_COME_HERE_LOOKING_TO_ENGAGE                                       = 8597,  -- You did not come here looking to engage in idle chitchat, nor would I dare to dampen the spirits of a fellow sensualist.
        UNTIL_WE_MEET_AGAIN_FOR_I_HAVE_A                                              = 8598,  -- Until we meet again, %, for I have a feeling that this is not the last we will see of each other.
        WHOA_WHOA_WHOA_HOLD_YOUR_CHOCOBOS_YOU_DO                                      = 8599,  -- Whoa, whoa, whoa! Hold your chocobos! You do realize that it's almost impossible to give you information on all the fruit harvested from the jungle this past year, right?
        HMMM_I_SEE                                                                    = 8600,  -- Hmmm. I see.
        IF_THAT_S_THE_CASE_THEN_YOU_RE                                                = 8601,  -- If that's the case, then you're looking for %.
        IT_ORIGINATED_FROM_WHERE_WAS_IT_AGAIN_OH                                      = 8602,  -- It originated from...where was it, again? Oh yes, the Middle Lands. A traveler who ventured to the Middle Lands brought it back with him when he returned.
        THE_TREE_HE_PLANTED_OUT_IN_THE_WOODS                                          = 8603,  -- The tree he planted out in the woods has been bearing fruit since the time of the Great Expedition, people say.
        THERE_USED_TO_BE_FIELDS_AND_GARDENS_THAT                                      = 8604,  -- There used to be fields and gardens that extended deep into the interior of the continent. I guess some survived after we Adoulinians fell back behind Jorius Yett.
        EVEN_IF_THEY_DO_SELL_FOR_A_HIGH                                               = 8605,  -- Even if they do sell for a high price, I know I'd never go foraging for them. It's simply too high a risk for the rate of return.
        STILL_I_CAN_SEE_THE_APPEAL_THEY_DON                                           = 8606,  -- Still, I can see the appeal. They don't grow in the Middle Lands anymore, so there is definitely a market for them.
        IF_YOU_WERE_TO_RAISE_A_PLANT_ALL                                              = 8607,  -- If you were to raise a plant all by yourself and then sell its yield abroad, you'd earn yourself a hefty profit for sure.
        COME_TO_THINK_OF_IT_I_RECALL_HEARING                                          = 8608,  -- Come to think of it, I recall hearing that the Civic Arboretum bought up all the remaining ones.
        IF_THAT_S_THE_CASE_I_M_CERTAIN                                                = 8609,  -- If that's the case, I'm certain there aren't any left. There's no way those botanophiles would let one slip through their thorny fingers.
        SORRY_I_COULDN_T_BE_ANY_MORE_OF                                               = 8610,  -- Sorry I couldn't be any more of a help to you.
        I_D_BEST_BE_GETTING_BACK_TO_WORK                                              = 8611,  -- I'd best be getting back to work now. Good luck in your search.
        OOOH_THE_LUMPY_GREEN_SNOT_FRUIT_OF_MY                                         = 8612,  -- Oooh, the lumpy green snot fruit of my youth! How'd ya manage t' find it?
        IN_YAHSE_HUNTING_GROUNDS_TALK_ABOUT_IT_BEING                                  = 8613,  -- In Yahse Hunting Grounds!? Talk about it being right under my nose the whole time! Too bad it was too stuffed with regrets from the past decades to sniff it out.
        THIS_ISN_T_THE_TIME_TO_BE_WALLOWING                                           = 8614,  -- This isn't the time to be wallowing in self-doubt! There's ambrosia t' drink here!
        HMMM_THAT_S_NOT_THE_FLAVOR_I_VE                                               = 8615,  -- ...Hmmm, that's not the flavor I've been longin' for, I tell you what.
        THE_FRUIT_LOOKS_THE_SAME_BUT_IT_AIN                                           = 8616,  -- The fruit looks the same, but it ain't got that telltale flavor.
        MUST_BE_DIFFER_NCES_IN_THE_SOIL_THAT                                          = 8617,  -- Must be differ'nces in the soil that done it. Ulbuka's never been the most conducive land t' farmin'.
        YOU_SAYIN_THAT_CAUSE_THERE_AIN_T_BE                                           = 8618,  -- You sayin' that 'cause there ain't be no more trees for it in the Middle Lands, I ain't never gettin' to taste the fruit like 'twas when I was younger?
        SO_MUCH_FOR_DYING_HAPPY                                                       = 8619,  -- So much for dying happy...
        WAIT                                                                          = 8620,  -- ...Wait.
        AFTER_TASTING_IT_AGAIN_DARE_I_SAY_THIS                                        = 8621,  -- After tasting it again, dare I say this ain't half bad!
        ODD_DESPITE_BEIN_REARED_UNDER_HARSH_CONDITIONS_ON                             = 8622,  -- Odd... Despite bein' reared under harsh conditions on this toughest of continents...it's like my grandma dripped honey down on it from the heavens!
        THIS_COULD_BE_EVEN_EASIER_T_DRINK_THAN                                        = 8623,  -- This could be even easier t' drink than the one I remember.
        YES_LET_ME_SAY_IT_LOUD_AND_PROUD                                              = 8624,  -- Yes. Let me say it loud and proud. This is one fine bev'rage!
        I_CAN_T_THANK_YOU_ENOUGH_THIS_WHOLE                                           = 8625,  -- %, I can't thank you enough. This whole time I'd been living in the past, tryin' to reclaim somethin' I couldn't...but you've opened my eyes.
        JUST_LIKE_HOW_THIS_NEW_ULBUKAN_GROWN_FRUIT                                    = 8626,  -- Just like how this new Ulbukan-grown fruit tastes better than the original, maybe what lies ahead of me ain't some inevitable march to the gallows!
        OF_COURSE_EVERYONE_S_GOTTA_MEET_THEIR_MAKER                                   = 8627,  -- Of course everyone's gotta meet their maker eventually, but that's no reason t' give up!
        MY_PURPOSE_FOR_LIVING_COULD_BE_HIDIN_IN                                       = 8628,  -- My purpose for living could be hidin' in the Yahse Hunting Grounds, too...or anywhere, even. All I need is a little rainwater and some quality soil to sink my roots into and start growin'.
        YOU_SAID_SOMETHIN_ABOUT_HOW_YOUNG_UNS_DOWN                                    = 8629,  -- You said somethin' about how young'uns down in them sewers was tryin' t' grow these on their own, didn'chya?
        THAT_GETS_ME_THINKIN_ABOUT_HOW_I_CAN                                          = 8630,  -- That gets me thinkin'...about how I can taste that heavenly flavor again...and how I wanna contribute t' Adoulin.
        I_HOPE_MY_DEAR_DEPARTED_WIFE_AIN_T                                            = 8631,  -- I hope my dear departed wife ain't get mad at me none for not keepin' her in my head ever' minute of the day, but I think I've found my life's callin'.
        I_MA_HEAD_ON_OVER_TO_THAT_ARBORETUM                                           = 8632,  -- I'ma head on over to that Arboretum and lend an old, wrinkly hand in raisin' those crops, for certain.
        I_WOULDN_T_HAVE_COME_T_THIS_REALIZATION                                       = 8633,  -- I wouldn't have come t' this realization without ya, %. This ain't worth the inspiration ya've given me, but at least it comes from the heart--the heart of a man born again.
        IF_A_PARTICULARLY_PIQUANT_FRUIT_IS_WHAT_YOU                                   = 8634,  -- If a particularly piquant fruit is what you're in search of, I suggest heading over to the Couriers' Coalition.
        NO_NEED_TO_THANK_ME_I_M_SURE                                                  = 8635,  -- No need to thank me. I'm sure you'll return the favor in due time. You are a pioneer, after all.
        RESEARCHERS_FROM_THE_CIVIC_ARBORETUM_BOUGHT_THE_TOTAL                         = 8636,  -- Researchers from the Civic Arboretum bought the total remaining stock of %, if what I've heard is to be believed.
        PERFECT_TIMING_AS_ALWAYS                                                      = 8637,  -- %! Perfect timing, as always.
        I_VE_HEARD_YOU_MADE_AN_APPEARANCE_AT                                          = 8638,  -- I've heard you made an appearance at one of the ruling class's post-colloquy banquets, have you not?
        WELL_THAT_CERTAINLY_WOULD_EXPLAIN_IT                                          = 8639,  -- Well, that certainly would explain it.
        AND_WITH_THE_WAY_YOU_VE_BEEN_COZYING                                          = 8640,  -- And with the way you've been cozying up to our dear princess of late, it only makes sense...
        LET_ME_SHARE_WITH_YOU_SOMETHING_JUICY_INGRID                                  = 8641,  -- Let me share with you something juicy. Ingrid of the Order of Weatherspoon is due to return to Adoulin from a brief sojourn to the Middle Lands.
        DON_T_BE_FOOLED_BY_HER_FAIR_COMPLEXION                                        = 8642,  -- Don't be fooled by her fair complexion and youthful attire--she is one of the order's most respected exorcists, with capabilities far beyond her years.
        INQUIRE_ABOUT_WHAT_WHAT_S_AN_EXORCIST_NEVER                                   = 8643,  -- Inquire about what? What's an exorcist? Never heard of them. ...
        YOU_GOT_ROCKS_FOR_BRAINS_LET_ME_SEE                                           = 8644,  -- You got rocks for brains? Let me see if I can explain this in the simplest terms possible.
        UNDEAD_BAD_NO_UNDEAD_GOOD                                                     = 8645,  -- Undead: bad. No undead: good.
        I_SUPPOSE_IT_IS_A_BIT_MORE_COMPLICATED                                        = 8646,  -- I suppose it is a bit more complicated than that. An exorcist is a white mage who focuses not on the path of rest and respite, but rather on smiting the wicked with divine fury.
        ALL_ADOULINIAN_TOTS_LEARN_THAT_THESE_CONJURERS_HAVE                           = 8647,  -- All Adoulinian tots learn that these conjurers have their roots in the sorcerous studies of the first head of Weatherspoon.
        AS_IS_OFTEN_SEEN_TECHNIQUES_WERE_PASSED_FROM                                  = 8648,  -- As is often seen, techniques were passed from progenitor to progeny, proving useful time and again until the citizenry of our fair city bore the exorcists naught but respect.
        A_LITTLE_HOLY_HERE_A_LITTLE_BANISH_THERE                                      = 8649,  -- A little Holy here, a little Banish there, and bam!
        THROUGHOUT_THE_AGES_THERE_HAVE_ALWAYS_BEEN_EXORCISTS                          = 8650,  -- Throughout the ages, there have always been exorcists with strong connections to the Order of Weatherspoon.
        IS_THAT_THE_REASON_WHY_UNDEAD_DO_NOT                                          = 8651,  -- Is that the reason why undead do not accost our fair city? The world may never know.
        YOU_KNOW_HOW_FOOT_SOLDIERS_GUARD_BIGWIGS_THAT                                 = 8652,  -- You know how foot soldiers guard bigwigs? That's the role exorcists play here in Adoulin.
        THE_LEADER_OF_THESE_SPIRITUALISTS_TURNED_SOLDIERS_IS                          = 8653,  -- The leader of these spiritualists-turned-soldiers is the high exorcist, Vortimere--an enigma to much of the city. What I am about to tell you comes directly from his lips.
        HAVE_ANY_QUESTIONS_SO_INGRID_IS_AN_EXORCIST                                   = 8654,  -- Have any questions? So Ingrid is an exorcist? What would Ingrid want with me?
        WERE_YOU_PAYING_ATTENTION_TO_A_WORD_I                                         = 8655,  -- Were you paying attention to a word I said? She's the creme de la creme of our prestigious exorcist chantry.
        DOESN_T_THAT_JUST_BEAT_ALL                                                    = 8656,  -- Doesn't that just beat all!
        RIGHT_AS_I_MENTIONED_INGRID_IS_THE_MOST                                       = 8657,  -- Right. As I mentioned, Ingrid is the most accomplished exorcist around. That is high praise in and of itself...
        BUT_SHE_S_ALSO_DROP_DEAD_GORGEOUS                                             = 8658,  -- ...But she's also drop-dead gorgeous!
        HER_PERSONALITY_IS_HOWEVER_A_BIT_HOW_CAN                                      = 8659,  -- Her personality is, however, a bit...how can I put this... Abrasive?
        ONE_TENET_OF_AN_EXORCIST_S_CREED_IS                                           = 8660,  -- One tenet of an exorcist's creed is that the wicked shall know no succor, and Ingrid takes this to such an extreme that the less diplomatic call her Ingrid the Merciless.
        BUT_LET_S_KEEP_THAT_JUST_BETWEEN_US                                           = 8661,  -- But let's keep that just between us.
        INQUIRE_ABOUT_WHAT_WHAT_WOULD_MS_MERCILESS_WANT                               = 8662,  -- Inquire about what? What would Ms. Merciless want with me? Ingrid the Merciless?
        H_HAVE_YOU_GONE_COMPLETELY_MAD_DON_T                                          = 8663,  -- H-have you gone completely mad!? Don't say that too loud, or they'll come for me, too!
        IF_YOUR_AIM_WAS_TO_CHOP_FIVE_YEARS                                            = 8664,  -- If your aim was to chop five years off my life, you've done an admirable job.
        BUT_BACK_TO_THE_MATTER_AT_HAND_INGRID                                         = 8665,  -- But back to the matter at hand. Ingrid expressed the desire to see more of the world, so she made a pilgrimage of sorts to the Middle Lands.
        BUT_SOMETHING_URGENT_CAME_UP_AND_SHE_IS                                       = 8666,  -- But something urgent came up, and she is now en route back to Adoulin.
        VORTIMERE_WOULD_HAVE_YOU_TAKE_A_STROLL_DOWN                                   = 8667,  -- Vortimere would have you take a stroll down to the airship docks and greet Ingrid when she arrives.
        PERHAPS_YOU_RE_WONDERING_WHY_HE_CHOSE_YOU                                     = 8668,  -- Perhaps you're wondering why he chose you.
        TO_BE_HONEST_I_ASKED_MYSELF_THE_SAME                                          = 8669,  -- To be honest, I asked myself the same thing. It must not be my place to know.
        BUT_A_REQUEST_IS_A_REQUEST_AND_HERE                                           = 8670,  -- But a request is a request, and here we find ourselves talking this lovely day.
        ONCE_SHE_ARRIVES_YOU_ARE_TO_ACCOMPANY_HER                                     = 8671,  -- Once she arrives, you are to accompany her to Adoulin Castle.
        YES_THE_CASTLE_NOT_THE_ORDER_OF_WEATHERSPOON                                  = 8672,  -- Yes, the castle. Not the Order of Weatherspoon manse.
        IT_VEXES_ME_TOO_BUT_VORTIMERE_SAID_TO                                         = 8673,  -- It vexes me, too, but Vortimere said to escort her directly there.
        WILL_YOU_GREET_INGRID_A_REAL_EXORCIST_YES                                     = 8674,  -- Will you greet Ingrid? A real exorcist? Yes! I'm a bit busy right now...
        I_M_SURE_HER_VESSEL_WILL_ARRIVE_AT                                            = 8675,  -- I'm sure her vessel will arrive at any moment, so you'd best hurry. She certainly would not take kindly to being kept waiting.
        I_VE_MADE_SURE_SHE_KNOWS_WHO_TO                                               = 8676,  -- I've made sure she knows who to look for, and I'll send word to the castle so they'll be expecting you.
        OFF_YOU_GO_THEN                                                               = 8677,  -- Off you go, then!
