        ARE_YOU_FAMILIAR_WITH_THIS_TIME_IN_ADOULIN                                    = 8722,  -- Are you familiar with this time in Adoulin's history?
        HAVE_YOU_HEARD_OF_THE_GREAT_EXPEDITION_O                                      = 8723,  -- Have you heard of the Great Expedition? O-of course! The what, now?
        YOUR_ANSWER_DOES_NOT_CONVINCE_ME_BUT_I                                        = 8724,  -- Your answer does not convince me, but I am loath to tell you something you may already know.
        THOSE_WHO_CANNOT_REMEMBER_THE_PAST_ARE_DOOMED                                 = 8725,  -- Those who cannot remember the past are doomed to repeat it. Pay a visit to % and become versed in the history of our fair city.
        MUTTER_CURSED_FOREIGNERS_CANNOT_EVEN_RESPECT_THE_LAND                         = 8726,  -- <Mutter> Cursed foreigners cannot even respect the land they are in...
        ALLOW_ME_TO_GIVE_YOU_A_BRIEF_LESSON                                           = 8727,  -- Allow me to give you a brief lesson. Colonization was attempted an additional time after the founder king's first foray all those years ago.
