        YOU_WISH_TO_EXCHANGE_YOUR_SPARKS                                              = 11362,  -- You wish to exchange your sparks?
        WAIT_BUT_A_MOMENT_HERE_FOLLOW_THIS_COMMAND                                    = 11363,  -- Wait but a moment. Here, follow this command--er, compendium to the letter and you should be able to learn a thing or two.
        AH_THIS_ALMOST_SLIPPED_MY_MIND_SHOULD_YOU                                     = 11364,  -- Ah, this almost slipped my mind. Should you receive any distinct sorts of artifacts for completing an objective, I will be happy to take them off your hands.
        WORRY_NOT_FOR_I_AM_NOT_OUT_TO                                                 = 11365,  -- Worry not, for I am not out to rob you of your glory. Quite the opposite, in fact. I will provide you with a worthwhile reward for collecting them.
        THANKS_TO_YOUR_DONATION_I_NOW_HAVE_IN                                         = 11366,  -- Thanks to your donation, I now have # in safekeeping.
        OHOHOHO_TURNING_IN_SPARKS_I_SEE                                               = 11367,  -- Ohohoho... Turning in sparks, I see.
        HOLD_YOUR_HOARDER_HARES_HERO_HEROINE_I_LOVE                                   = 11368,  -- Hold your hoarder hares, hero/heroine]. I love your enthusiasm, but you're not going to learn a thing without a primer. Ahhh, here it is. Have a look-see.
