        POURED_WATER_INTO_THE_GOBLET_THERE_CURRENTLY_ONZ                              = 12222,  -- [You/Etienne] poured water into the goblet. There [is/are] currently # onz[/es] of water in it.
        POURED_WATER_INTO_THE_GOBLET_CAUSING_IT_TO                                    = 12223,  -- [You/Etienne] poured water into the goblet, causing it to overflow. [You have bested your challenger. Claim what is yours by lapping the tears of defeat from his face and tasting the glorious sorrow contained within./How does complete and utter defeat feel? Will you even be able to sleep once night falls?]
        SHOULD_YOU_SEEK_SALVATION_BY_ENHANCING_YOUR_EQUIPMENT                         = 12224,  -- Should you seek salvation by enhancing your equipment through arcane glyptics, simply bequeath the requisite materials and equipment to me and I shall work my magic.
