        WHAT_SHALL_YOU_DO_BAYLD_NOT_A_THING                                           = 12245,  -- What shall you do? (Bayld: #) Not a thing. Mezzotint equipment. Check materials required. Inquire about arcane glyptics.
        ARCANE_GLYPTICS_ARE_TRULY_ASTOUNDING_ENGRAVINGS_THEY_CAN                      = 12246,  -- Arcane glyptics are truly astounding engravings--they can be used to enhance a cornucopia of equipment you find during your pioneering journeys! However, they cannot work their magic until the article in question undergoes a priming process called mezzotinting.
        THERE_ARE_THREE_GLYPTIC_PATHS_DOWN_WHICH_YOU                                  = 12247,  -- There are three glyptic paths down which you may send your equipment. All of them differ in significant ways and will not fail to treat your beloved accouterments right.
        MOREOVER_YOUR_INANIMATE_COMRADES_IN_COMBAT_CAN_BE                             = 12248,  -- Moreover, your inanimate comrades in combat can be further enhanced by employing materials such as % during glyptic engraving.
        I_MUST_WARN_YOU_HOWEVER_THAT_THE_PROCESS                                      = 12249,  -- I must warn you, however, that the process is not instantaneous. We will need to engrave your articles multiple times before any glyptics take effect.
        THINK_OF_IT_LIKE_YOUR_PIONEERING_ACTIVITIES_ULBUKA                            = 12250,  -- Think of it like your pioneering activities. Ulbuka cannot be colonized in a day, nor can we improve your equipment in one try if we want to do a satisfactory job. In addition, your equipment may undergo mezzotinting any time you wish to set it down a new path to clearing the continent of danger. Simply ask and you shall receive.
        LEST_I_FORGET_I_SHOULD_ALSO_MENTION_THAT                                      = 12251,  -- Lest I forget, I should also mention that a fee of # bayld is required for the first mezzotinting, while # is the price for subsequent ones and enhancement via materials.
        YOUR_HAS_ALREADY_BEEN_ENGRAVED_WITH_AN_ARCANE                                 = 12252,  -- Your % has already been engraved with an arcane glyptic, the benefits of which will be lost upon mezzotinting. Do you still wish to proceed?
        PROCEED_WITH_MEZZOTINTING_YES_SCRAPE_ALL_THE_EXCESS                           = 12253,  -- Proceed with mezzotinting? Yes, scrape all the excess benefits away! No, I love my little precious too much!
        WHICH_TYPE_OF_GLYPTICS_SHALL_YOU_ENGRAVE                                      = 12254,  -- Which type of glyptics shall you engrave?
        WHICH_TYPE_DO_YOU_WANT_ENGRAVED_NONE_ARCANE                                   = 12255,  -- Which type do you want engraved? None. Arcane Glyptic Type A. Arcane Glyptic Type B. Arcane Glyptic Type C.
        DO_YOU_WISH_TO_MEZZOTINT_YOUR_WEAPON_SO                                       = 12256,  -- Do you wish to mezzotint your weapon so that it is primed to receive the aforementioned attribute enhancements?
