        THIS_LOOKS_AS_IF_IT_CAN_BE_ENGRAVED                                           = 12261,  -- This % looks as if it can be engraved with a peculiar sort of arcane glyptic. It may behoove you to show this to the person in charge of such procedures.
        TAKE_A_GANDER_AT_WHAT_NOTHING_EQUIPMENT_MATERIALS                             = 12262,  -- Take a gander at what? Nothing. Equipment. Materials.
