        TO_WIN_THIS_GREATEST_AMUSEMENT_ON_VANA_DIEL                                   = 12303,  -- To win this greatest amusement on Vana'diel, you must collect suit and number combinations of the three cards you are dealt. Each card will be imprinted with one of four suits and six numbers.
        IT_IS_POSSIBLE_TO_TRADE_IN_A_MAXIMUM                                          = 12304,  -- It is possible to trade in a maximum of three times, and the amount of cards you draw is equal to the number you discard. Of course, it is acceptable to step down from exchanging should you feel you are walking on a tightrope.
        AS_FOR_THE_COMBINATIONS_EACH_ONE_IS_WORTH                                     = 12305,  -- As for the combinations, each one is worth a different number of points. In the event that all three of your cards display different numbers, only the largest one shall count toward your point total.
        IF_YOU_POSSESS_A_PAIR_YOU_GAIN_A                                              = 12306,  -- If you possess a pair, you gain a number of points equal to twice the number of your remaining card.
