        HERE_IS_HOW_THE_COALITION_CONTRIBUTES_TO_IONIS                                = 12374,  -- Here is how the [Pioneers'/Peacekeepers'/Couriers'/Scouts'/Inventors'/Mummers'] Coalition contributes to Ionis.
        WHOOPS_IT_SEEMS_THEY_DO_NOT_ADD_ANY                                           = 12375,  -- Whoops, it seems they do not add any additional effects.
