        BASED_ON_THE_STATE_OF_THEIR_EXPANSION_A_3                                     = 12378,  -- Based on the state of their expansion, a [Minor Accuracy and Magic Accuracy Enhancement/Minor Evasion and Magic Evasion Enhancement/Minor Critical Hit Rate Increase/Minor Haste Effect/Moderate Accuracy and Magic Accuracy Enhancement/Moderate Evasion and Magic Evasion Enhancement/Moderate Critical Hit Rate Increase/Moderate Haste Effect] will be bestowed upon you.
        BASED_ON_THE_STATE_OF_THEIR_EXPANSION_A_4                                     = 12379,  -- Based on the state of their expansion, a [Minor Save TP Effect/Minor Conserve MP Effect/Minor Fast Cast Effect/Minor Resistance Increase to All Status Ailments/Moderate Save TP Effect/Moderate Conserve MP Effect/Moderate Fast Cast Effect/Moderate Resistance Increase to All Status Ailments] will be bestowed upon you.
        BASED_ON_THE_STATE_OF_THEIR_EXPANSION_A_5                                     = 12380,  -- Based on the state of their expansion, a [Minor Crystal Obtainment Rate Increase/Minor Material Loss Rate Reduction/Minor Synthesis Skill Gain Rate Increase/Minor Synthesis Success Rate Increase/Moderate Crystal Obtainment Rate Increase/Moderate Material Loss Rate Reduction/Moderate Synthesis Skill Gain Rate Increase/Moderate Synthesis Success Rate Increase] will be bestowed upon you.
        BASED_ON_THE_STATE_OF_THEIR_EXPANSION_A_6                                     = 12381,  -- Based on the state of their expansion, a [Minor Combat Skill Gain Rate Increase/Minor Magic Skill Gain Rate Increase/Minor Experience Point Bonus/Minor Reward Obtainment Rate Increase/Moderate Combat Skill Gain Rate Increase/Moderate Magic Skill Gain Rate Increase/Moderate Experience Point Bonus/Moderate Reward Obtainment Rate Increase] will be bestowed upon you.
        WHAT_A_TRICKY_QUESTION_WELL_IT_IS_A                                           = 12382,  -- What a tricky question. Well...it is a thaumaturgical aura that grants multitudes of benefits to pioneers.
        WHAT_IS_TRULY_INTERESTING_IS_THAT_THIS_AURA                                   = 12383,  -- What is truly interesting is that this aura draws its powers from the various coalitions. The larger they grow, the more powerful the benefits each one will provide.
        THE_MORE_PIONEERING_FEATS_YOU_PERFORM_THE_MORE                                = 12384,  -- The more pioneering feats you perform, the more the coalitions develop, and the more beneficial Ionis becomes. Think of it as a virtuous cycle!
        YOU_HAVE_BEEN_IMBUED_WITH_THE_POWER_OF                                        = 12385,  -- You have been imbued with the power of Ionis!
        W_W_WAIT_HUFF_PUFF_MY_MY_NAME                                                 = 12386,  -- W-w-wait!!! <Huff> <Puff> My...my name's Sylvie. Pleased to...to make your acquaintance, hee hee!
        HUFF_SORRY_I_M_AN_OUT_OF_SHAPE                                                = 12387,  -- <Huff> ...Sorry, I'm an out-of-shape geomancer...and not a people person.
        BUT_IKHI_ASKAMOT_HERSELF_HAS_CHARGED_ME_WITH                                  = 12388,  -- But Ikhi Askamot herself has charged me with this most splendiferous of responsibilities to help me overcome my shortcomings!
        AHHHHHH_UHHH_MY_TASK_WELL_UM_IT_S                                             = 12389,  -- Ahhhhhh, uhhh, my task? Well, um, it's to help bring new geomancers into the fold. Yaaaaaay!
        TO_TELL_THE_TRUTH_THE_ORDER_OF_RENAYE                                         = 12390,  -- To tell the truth, the Order of Renaye is...kind of opposed to this whole pioneering thingamajig.
        BUT_BUT_IF_ADOULIN_NEEDS_OUR_ASSISTANCE_WE                                    = 12391,  -- But! But! If Adoulin needs our assistance, we're gonna do everything we can!
        PLUS_EASTERN_ULBUKA_S_SCENERY_SCARES_ME_WITH                                  = 12392,  -- Plus, Eastern Ulbuka's scenery scares me with its trees and rivers--without geomancers to lend their aid, what hope does the land have?
        AND_YOU_YOU_LOOK_LIKE_THE_GEODANCING_TYPE                                     = 12393,  -- And you...you look like the geodancing type! Right? Right!?
        YOUR_MOVE_WHA_SLOW_DOWN_NELLIE                                                = 12394,  -- Your move. Wha...? Slow down, Nellie.
        I_YES_WELL_GEOMANCERS_YOU_WANNA_BE_ONE                                        = 12395,  -- I...yes, well...geomancers! You wanna be one, don'tcha?
        SORRY_I_M_NOT_TERRIBLY_GOOD_AT_THIS                                           = 12396,  -- ...Sorry. I'm not terribly good at this sort of thing.
        TRY_YOUR_HAND_AT_GEOMANCY_I_D_LOVE                                            = 12397,  -- Try your hand at geomancy? I'd love to give it a go! Sounds like fun!
        R_REALLY_OH_HOW_MAGNANITABULAR                                                = 12398,  -- R-really!? Oh, how magnanitabular!
        YOU_RE_REALLY_SURE_I_MEAN_REALLY_REALLY                                       = 12399,  -- You're really sure? I mean really, really sure???
        HOORAY_THEN_LET_S_ROLL_UP_OUR_SLEEVES                                         = 12400,  -- Hooray! Then let's roll up our sleeves and get started!
        FIRST_A_QUIZ_WHAT_S_ADOULIN_S_OLDEST                                          = 12401,  -- First, a quiz! What's Adoulin's oldest profession? That's right...geomancy!
        BUT_WELL_EVEN_THOUGH_IT_WAS_KNOWN_FOR                                         = 12402,  -- But, well, even though it was known for, well, since forever, it never really took off until much later.
        I_M_A_LITTLE_FUZZY_ON_THE_DETAILS                                             = 12403,  -- I'm a little fuzzy on the details. It's complicated. Something about the sirens of legends, or the five disciples of Sih Renaye... Gosh, I can never keep this stuff straight.
        OH_WAIT_GEOMANCY_RIGHT                                                        = 12404,  -- Oh, wait! Geomancy. Right.
        RESEARCH_INTO_GEOMANCY_AS_A_DISCIPLINE_STARTED_WELL                           = 12405,  -- Research into geomancy as a discipline started...well, started in Eastern Ulbuka as a way to counteract the dangers of nature, and took place over many, many years.
        IT_S_KINDA_SIMILAR_TO_YET_TOTALLY_DIFFERENT                                   = 12406,  -- It's kinda similar to, yet totally different from, the pioneering efforts that occurred back then. What geomancy cares about is having a heart-to-heart with nature.
        BUT_THAT_S_AT_A_REALLY_ADVANCED_LEVEL                                         = 12407,  -- But that's at a really advanced level. Back then, only the best of the best could do it.
        WELL_YOU_KNOW_NATURAL_FORCES_CAN_BE_A                                         = 12408,  -- Well, you know...natural forces can be a bit cheeky, and don't like it when people try to expose their feelings.
        EVENTUALLY_THE_ANCIENT_GEOMANCERS_REALIZED_THAT_THE_ANSWER                    = 12409,  -- Eventually, the ancient geomancers realized that the answer wasn't to control the land--could you imagine?--but rather let themselves be swept up by its current and borrow some of its strength.
        WE_CALL_THAT_CURRENT_THE_LIFESTREAM_THE_LIFESTREAM                            = 12410,  -- We call that current the lifestream. The lifestream flows within Mother Nature kinda like how blood flows through you and me. It's all around us, even right now.
        WHEN_WE_USE_THE_POWER_OF_THE_LIFESTREAM                                       = 12411,  -- When we use the power of the lifestream, it's called using Geomantic Incantations, or simply Geomancy. Confusing, right? I know it threw me for a loop, having two words mean the same thing...
        THERE_ARE_TWO_TYPES_OF_GEOMANCY_POWER_ORIGINATING                             = 12412,  -- There are two types of geomancy. Power originating from the geomancer herself is known as Indi, and power originating from a mystic emanation known as a luopan is called Geo.
        IKHI_ASKAMOT_SAYS_THAT_ANCIENT_GEOMANCERS_GAVE_NAMES                          = 12413,  -- Ikhi Askamot says that ancient geomancers gave names to all these terms to help people understand, but she also thinks that it's easier to just see for yourself.
        IT_S_LIKE_THAT_OLD_SAYING_YOU_KNOW                                            = 12414,  -- It's like that old saying, you know? A picture is worth two in the bush, or something...? Sorry, I'm really bad at this.
        COME_ON_YOU_KNOW_WHAT_I_MEAN_IF                                               = 12415,  -- Come on, you know what I mean! If you get your hands wet you'll learn more than if I blab on about it for hours.
        S_SO_IN_ORDER_TO_HANDLE_THE_EXCELLENTATIOUSNESS                               = 12416,  -- S-so! In order to handle the excellentatiousness of geomancy, you first need a luopan!
        LUOPANS_ARE_ESSENTIAL_FOR_BEING_A_WORLD_CLASS                                 = 12417,  -- Luopans are essential for being a world-class geomancer. They're like a loyal pet--until death do you part!
        EXCEPT_LUOPANS_DON_T_RUN_AWAY_ONE_AFTERNOON                                   = 12418,  -- Except luopans don't run away one afternoon when you're seven years old, leaving you crying on your front doorstep.
        COURSE_MOST_GEOMANCERS_CAN_T_USE_LUOPANS_RIGHT                                = 12419,  -- 'Course, most geomancers can't use luopans right after they become one. Become geomancers, I mean.
        LECTURE_S_OVER_READY_TO_GET_DOWN_AND                                          = 12420,  -- Lecture's over! Ready to get down and dirty?
        MAKE_A_LUOPAN_YES_NO                                                          = 12421,  -- Make a luopan? Yes! .........No.
        WH_WHAT_I_VE_BEEN_SITTING_HERE_POURING                                        = 12422,  -- Wh-what? I've been sitting here pouring my heart out, and you're gonna walk away just like that?
        I_KNEW_I_WASN_T_CUT_OUT_FOR                                                   = 12423,  -- I knew I wasn't cut out for this... Oh, Ikhi, I did it again...
        YOU_REALLY_MEAN_IT_YOU_RE_GOING_TO                                            = 12424,  -- You...really mean it? You're going to try?
        THIS_IS_STUPENDELICIOUS                                                       = 12425,  -- This is stupendelicious!
        LET_S_GET_THIS_PARTY_STARTED_BEFORE_YOU                                       = 12426,  -- Let's get this party started before you bail on me!
        GETTING_THE_MATERIALS_FOR_A_LUOPAN_IS_REALLY                                  = 12427,  -- Getting the materials for a luopan is really simple, so I know you'll be up for it.
        YOU_LL_NEED_TWO_THINGS_ONE_AND                                                = 12428,  -- You'll need two things--one % and %.
        THE_LUOPAN_IS_A_MEDIUM_FOR_YOU_TO                                             = 12429,  -- The luopan is a medium for you to get all friendly with nature. That's why you need the %.
        YOU_RE_FROM_THE_MIDDLE_LANDS_NOT_ADOULIN                                      = 12430,  -- You're from the Middle Lands, not Adoulin, so to make a really super-duper one, you should find some from an area in your homeland where energies flow through the soil.
        THAT_S_ALL_YOU_NEED_EASY_PEASY_LEMON                                          = 12431,  -- That's all you need! Easy peasy, lemon squeezy. Just come back to me when you've got 'em!
        CAME_BACK_FOR_A_REMINDER_ON_WHAT_YOU                                          = 12432,  -- Came back for a reminder on what you need for your luopan?
        RIGHT_ALL_YOU_NEEDED_WAS_THE_PERFECT_COMBINATION                              = 12433,  -- Right, all you needed was the perfect combination of % and %!
        ALL_RIGHT_LET_ME_HAVE_AT_EM                                                   = 12434,  -- All right, let me have at 'em!
        GULP_2                                                                        = 12435,  -- <Gulp>...
        A_ACK                                                                         = 12436,  -- A-ack!!!
        HEAVE_AND_COUGH_OH_NO_I_PHEW                                                  = 12437,  -- <Heave> And... <Cough> Oh no, I... Phew!
        GRUNT                                                                         = 12438,  -- <Grunt>
        OH_UGLY_UMBRILS_I_ALMOST_HAD_A_HEART                                          = 12439,  -- Oh, ugly umbrils! I almost had a heart attack!
        SORRY_ABOUT_THAT_HERE_S_YOUR_FRESH_SHINY                                      = 12440,  -- Sorry about that. Here's your fresh, shiny luopan!
        YES_FRESH_AND_SHINY_BUT_NOT_YET_DONE                                          = 12441,  -- Yes, fresh and shiny...but not yet done!
        IT_S_GOTTA_GO_TO_AN_ERGON_LOCUS                                               = 12442,  -- It's gotta go to an ergon locus first.
        IT_IS_ONLY_IN_THESE_PLACES_DEEPLY_CONNECTED                                   = 12443,  -- It is only in these places, deeply connected with nature herself, that your luopan will be able to display its...<whisper> immense power.
        AH_ERGON_LOCUS_RIGHT_IT_S_LIKE_I                                              = 12444,  -- Ah! Ergon locus, right. It's like I told you--places filled with natural power.
        THOUGH_THEY_EXIST_THROUGH_ALL_OF_VANA_DIEL                                    = 12445,  -- Though they exist through all of Vana'diel, here in Adoulin we call them ergon loci.
        YOU_CAME_INTO_CONTACT_WITH_THEM_IN_THE                                        = 12446,  -- You came into contact with them in the Middle Lands, I'm sure. Depending on the era and locale, some of them go by different names...I guess.
        ONE_OF_THE_FRUITS_LOW_HANGING_FRUIT_PERHAPS                                   = 12447,  -- One of the fruits--low-hanging fruit, perhaps--of this pioneering whosy-whatsit is that we've discovered ergon loci in the Yahse Hunting Grounds and the Ceizak Battlegrounds.
        I_GOTTA_BE_HONEST_WITH_YOU_AS_A                                               = 12448,  -- I gotta be honest with you. As a geomancer, I'm not a big fan of messing with nature.
        BUT_SOMETIMES_YOU_GOTTA_TAKE_A_LONG_TERM                                      = 12449,  -- But sometimes you gotta take a long-term view, y'know?
        THIS_WHOLE_TUG_OF_WAR_BETWEEN_NATURE_AND                                      = 12450,  -- This whole tug-of-war between nature and progress has always defined what Adoulin is.
        TOHOHO_LISTEN_TO_ME_THAT_WAS_TOTALLY_DEEP                                     = 12451,  -- Tohoho, listen to me! That was totally deep, right?
        WHERE_WERE_WE_OH_RIGHT_ERGON_LOCI_BRING                                       = 12452,  -- ...Where were we? Oh, right, ergon loci. Bring your luopan to one of these loci and remain calm and steady.
        LIKE_THIS_SEE                                                                 = 12453,  -- Like this, see?
        YOU_GOTTA_BE_FOCUSED_OR_ELSE_IT_WON                                           = 12454,  -- You gotta be focused, or else it won't work. It's the first step in becoming one with nature. Let the lifestream gently flow into your luopan.
        YOU_LL_GET_ALL_HOT_AND_BOTHERED_SO                                            = 12455,  -- You'll get all hot and bothered, so you'll know when it's happening. This is another one of those two in the bush things.
        AND_JUST_WHEN_YOU_THINK_YOU_VE_HAD                                            = 12456,  -- And just when you think you've had all you can stand and are about to explode...you'll finish and feel the warm embrace of release.
        I_LL_HAVE_TO_TOUCH_UP_YOUR_LUOPAN                                             = 12457,  -- I'll have to touch up your luopan when you're done, so make sure to come back!
        YOU_KNOW_THE_FOREST_ISN_T_THE_FRIENDLIEST                                     = 12458,  -- You know...the forest isn't the friendliest of locations. I'd hate for anything to happen to your precious luo--<cough> to you.
        THERE_YOU_HAVE_IT_NOW_GET_GOING                                               = 12459,  -- There you have it! Now get going!
        THIS_IS_POSITIVELY_MOMENTERRIFIC_T_LET_ME_GET                                 = 12460,  -- This is positively momenterrific!t Let me get a good look...
        THERE_I_APPLIED_A_THIN_ASTRAL_PATINA_TO                                       = 12461,  -- ...There! I applied a thin astral patina to your luopan to keep it in tip-top shape. Now you can use it in your geomantic adventures!
        YOU_KNOW_IKHI_SAID_THAT_THIS_LUOPAN_BUSINESS                                  = 12462,  -- You know, Ikhi said that this luopan business was brought to Adoulin ten-something years ago by a woman from abroad. Quite the convenience, wouldn't you say?
        WHISPER_SHE_ALSO_SAID_THAT_SAME_WOMAN_TAUGHT                                  = 12463,  -- <Whisper> She also said that same woman taught us about the waypoints. <Cough> I don't know much more about it.
        SORRY_I_WAS_RAMBLING_AGAIN_WASN_T_I                                           = 12464,  -- ...Sorry! I was rambling again, wasn't I?
        ANYWAY_YOU_CAN_T_ACTUALLY_USE_YOUR_LUOPAN                                     = 12465,  -- Anyway, you can't actually use your luopan to its full extent unless you become more experienced in geomancy.
        AWW_LOOK_AT_YOU_WITH_THOSE_SAD_EYES                                           = 12466,  -- Aww, look at you with those sad eyes. Fear not! It won't be long before you've mastered both parts of geomancy!
        DON_T_TELL_ME_YOU_FORGOT_WHAT_THEY                                            = 12467,  -- Don't tell me you forgot what they are already! ...Fine, let's review. Indi spells are energy centered around the geomancer, while Geo spells are energy centered around the luopan.
        IT_S_PROBABLY_EASIER_IF_I_JUST_SHOW                                           = 12468,  -- It's probably easier if I just show you.
        THIS_IS_INDI                                                                  = 12469,  -- This is Indi...
        AND_THIS_IS_GEO                                                               = 12470,  -- ...And this is Geo.
        THOSE_MORE_EXPERIENCED_WITH_THE_WAYS_OF_THE                                   = 12471,  -- Those more experienced with the ways of the geomancer get to use both at once! Not a bad deal, if you ask me. As an aside, the fields created by Indi and Geo are collectively known as Colures.
        WHEN_WE_USE_THE_TERMS_INDI_AND_GEO                                            = 12472,  -- When we use the terms Indi and Geo, we are simply using the short form of Indicolures and Geocolures.
        THIS_IS_PROBABLY_A_LOT_TO_TAKE_IN                                             = 12473,  -- This is probably a lot to take in. Don't lose heart, though--you'll be a magnifferific geomancer before you know it!
        AND_NOW_BY_THE_POWERS_VESTED_IN_ME                                            = 12474,  -- And now, by the powers vested in me, I declare you geomancer and luopan.
        AH_WAIT_ALL_THIS_TIME_AND_I_NEVER                                             = 12475,  -- Ah, wait! All this time, and I never even asked your name!
        IT_WAS_A_PLEASURE_WORKING_WITH_YOU                                            = 12476,  -- %, it was a pleasure working with you!
        WITH_ALL_YOU_VE_DONE_TO_GET_THIS                                              = 12477,  -- With all you've done to get this far, you must be itching for some kind of prize. Normally the luopan itself would be enough, but you've been such a good sport that I got you a little gift.
        THIS_IS_CALLED_A_GEOMANTIC_HANDBELL_WITH_IT                                   = 12478,  -- This is called a geomantic handbell. With it, you can bring out the true strength of your geomancy spells. Just don't forget to equip it and leave it in your back pocket like the last initiate, hmm?
        AND_ANOTHER_PRESENT_FOR_YOU_THIS_IS_YOUR                                      = 12479,  -- And another present for you. This % is your first official weapon in your geomantic arsenal. Make sure you use it wisely!
        THANKS_FOR_PUTTING_UP_WITH_A_DITZY_KLUTZ                                      = 12480,  -- Thanks for putting up with a ditzy klutz like me all this time!
        MAYBE_ONE_DAY_YOU_LL_BECOME_AS_FANTABULACIOUS                                 = 12481,  -- Maybe one day you'll become as fantabulacious of a geomancer as I am!
        YOU_WHAT_WHO_GOES_AROUND_THROWING_AWAY_A                                      = 12482,  -- You what!? Who goes around throwing away a perfectly good handbell!?
        I_THOUGHT_I_D_MADE_IT_PERFECTLY_CLEAR                                         = 12483,  -- I thought I'd made it perfectly clear how it was almost as important as your luopan...
        FINE_FINE_I_LL_LET_YOU_HAVE_ANOTHER                                           = 12484,  -- Fine, fine. I'll let you have another handbell--but because it was your fault, you get to shoe the bill.
        I_ACCEPT_PAYMENT_IN_THE_FORM_OF_EITHER                                        = 12485,  -- I accept payment in the form of either # gil or # bayld.
        SO_HOW_IS_THIS_TRANSACTION_GONNA_GO_DOWN                                      = 12486,  -- So? How is this transaction gonna go down?
        SELECT_YOUR_PAYMENT_METHOD_HANG_ON_GIL_BAYLD                                  = 12487,  -- Select your payment method. Hang on. Gil. Bayld.
        ARE_YOU_REEEALLY_SURE_NO_TRUE_GEOMANCER_WOULD                                 = 12488,  -- Are you reeeally sure? No true geomancer would ever go without their bell!
        LET_S_SEAL_THE_DEAL_THEN                                                      = 12489,  -- Let's seal the deal, then.
        HERE_S_YOUR_NEW_HANDBELL_PLEASE_KEEP_BETTER                                   = 12490,  -- Here's your new handbell. Please keep better track of this one, okay?
        HMM_YOU_DON_T_SEEM_TO_HAVE_ENOUGH                                             = 12491,  -- Hmm...you don't seem to have enough. I can't let you have a new one just because you have a pretty face.
        UMM_HMMM_I_DON_T_THINK_THIS_GUY                                               = 12492,  -- Umm, hmmm.... I don't think this guy/gal] can do it...
        WHAT_S_THIS_THEN_YOU_CAN_T_CARRY                                              = 12493,  -- What's this then? You can't carry any more? Lemme know when you've get everything sorted out, and we'll do this again!
        YOU_HAND_THE_CLERK_THE_AND_GIL_AND                                            = 12494,  -- You hand the clerk the % and # gil, and your set of armor is returned.
        HELLO_SIR_MA_AM_HAVE_YOU_EVER_FOUND                                           = 12495,  -- Hello, sir/ma'am]. Have you ever found yourself throwing away items because your Mog Safe is overflowing with dusty sets of armor collected on your many adventures? My colleagues and I have heard the cries of our fellow adventurers and joined together to aid all those in need.
        TRADE_ME_A_FULL_SET_AND_FOR_A                                                 = 12496,  -- Trade me a full set, and for a small fee (payable on pickup) we will hold on to it, all the while protecting it from thieves, moths, and any/all acts of god and/or goddess.
