        BUT_THERE_IS_SOMEONE_ELSE_ON_OUR_SIDE                                         = 12693,  -- But there is someone else on our side--a hero who was there to witness it all.
        WHO_IS_SHE_REFERRING_TO_SAJJ_AKA_MORIMAR                                      = 12694,  -- Who is she referring to? Sajj'aka. Morimar.
        THAT_S_RIGHT_HE_FOUGHT_ALONGSIDE_THE_FOUNDER                                  = 12695,  -- That's right. He fought alongside the founder king, and ever since has tirelessly worked to shield Ulbuka from harm. If anyone can help us, it's him.
