        ID_12832                                                                      = 12832,  -- #<#
        URK_2                                                                         = 12833,  -- Urk!
        I_UNDERSTAND_THAT_YOU_ARE_AN_ADVENTURER_MY                                    = 12834,  -- I understand that you are...an adventurer? My name is Pieuje I. d'Oraguille, commander of San d'Oria's famed Temple Knights.
        IS_THAT_S_VOICE_I_HEAR                                                        = 12835,  -- Is that %'s voice I hear?
        FORGIVE_ME_BUT_I_AM_MORE_ACCUSTOMED_TO                                        = 12836,  -- Forgive me, but I am more accustomed to recognizing faces than voices, especially through such a peculiar device.
        I_MUST_THANK_YOU_FOR_YOUR_HANDLING_OF                                         = 12837,  -- I must thank you for your handling of the Altedour incident in Fei'Yin.
        NEVER_ONCE_HAVE_I_FORGOTTEN_YOUR_DEDICATION_TO                                = 12838,  -- Never once have I forgotten your dedication to protecting all of San d'Oria.
        AS_YOU_ARE_DOUBTLESSLY_AWARE_A_SHORT_TIME                                     = 12839,  -- As you are doubtlessly aware, a short time ago I received a memorandum from the Adventurers' Mutual Aid Network detailing Unity Concord and requesting my services as a Unity leader.
        TELL_ME_IS_THERE_ANY_GREATER_WAY_FOR                                          = 12840,  -- Tell me. Is there any greater way for a prince regent to earn honor for his kingdom than by spearheading a group dedicated to purging evil from the land?
        MANY_AROUND_ME_WERE_OPPOSED_BUT_THAT_BOTHERED                                 = 12841,  -- Many around me were opposed, but that bothered me not. My brother, Trion, serves as a representative of the Trust initiative, and it falls to me to up the ante.
        I_CANNOT_LIE_THAT_WAS_AN_IMPORTANT_FACTOR                                     = 12842,  -- I cannot lie. That was an important factor in my decision.
