        UNITY_CONCORD_IS_A_SYSTEM_PROMULGATED_AND_MANAGED                             = 13034,  -- Unity Concord is a system promulgated and managed by the Adventurers' Mutual Aid Network.
        PARTICIPATING_ADVENTURERS_ARE_ABLE_TO_RECEIVE_A_VARIETY                       = 13035,  -- Participating adventurers are able to receive a variety of benefits and rewards just by engaging in their everyday activities.
        UNITY_IS_A_CATCHALL_TERM_THAT_REFERS_TO                                       = 13036,  -- Unity is a catchall term that refers to the group that participants belong to.
        UNITY_LEADERS_ARE_INDIVIDUALS_WHO_HAVE_STRONG_TIES                            = 13037,  -- Unity leaders are individuals who have strong ties to adventurers' activities and are sterling representatives of their home nations.
        MEMBERS_OF_THE_SAME_UNITY_CAN_CONVERSE_WITH                                   = 13038,  -- Members of the same Unity can converse with each other over great distances through the use of specialized figurines known as %.
        CHAT_SETTINGS_MAY_BE_CHANGED_BY_SELECTING_STATUS                              = 13039,  -- Chat settings may be changed by selecting Status from the main menu, and choosing Unity Info under the Unity submenu.
        YOU_MAY_NOT_ALWAYS_BE_ABLE_TO_JOIN                                            = 13040,  -- You may not always be able to join the chat if too many players are participating at once.
        THOSE_BELONGING_TO_A_UNITY_ARE_ABLE_TO                                        = 13041,  -- Those belonging to a Unity are able to undertake special Records of Eminence objectives related to Unity Concord activities.
        THE_THREE_PERTINENT_CATEGORIES_INCLUDE_SHARED_OBJECTIVES_UNITY                = 13042,  -- The three pertinent categories include shared objectives, Unity leader-specific objectives, and Wanted battle objectives.
        SHARED_OBJECTIVES_MAY_BE_TAKEN_REGARDLESS_OF_WHICH                            = 13043,  -- Shared objectives may be taken regardless of which Unity you have joined. These tasks can be undertaken at any time, and change every day at midnight (JST).
        UNITY_LEADER_SPECIFIC_OBJECTIVES_ARE_TIED_TO_THE                              = 13044,  -- Unity leader-specific objectives are tied to the Unity's eponymous leader and change each week.
        WANTED_OBJECTIVES_CENTER_AROUND_VANQUISHING_PARTICULARLY_HEINOUS_FOES         = 13045,  -- Wanted objectives center around vanquishing particularly heinous foes that terrorize Vana'diel.
        THESE_OBJECTIVES_ARE_OF_A_HIGHER_CALIBER_AND                                  = 13046,  -- These objectives are of a higher caliber, and thus require currency known as Unity accolades to undertake.
        SHARED_AND_LEADER_SPECIFIC_OBJECTIVES_PROVIDE_MORE_ACCOLADES                  = 13047,  -- Shared and leader-specific objectives provide more accolades than run-of-the-mill objectives.
        VANA_DIEL_HAS_ALWAYS_BEEN_PLAGUED_BY_NEFARIOUS                                = 13048,  -- Vana'diel has always been plagued by nefarious foes pillaging the landscape, but relatives of some of the more heinous ones have been spotted lately.
        THE_A_M_A_N_HAS_DEEMED_IT                                                     = 13049,  -- The A.M.A.N. has deemed it necessary to eliminate these Wanted targets, and has notified Unity members that they are of the utmost priority.
        A_LIST_OF_THESE_FOES_CAN_BE_VIEWED                                            = 13050,  -- A list of these foes can be viewed at any time by selecting the appropriate subcategory under the objectives list.
        UNITY_CONCORD_REPRESENTATIVES_ARE_ABLE_TO_PROVIDE_PARTICIPANTS                = 13051,  -- Unity Concord representatives are able to provide participants with transportation to the areas where these threats can be found.
        THOUGH_TACKLING_THE_PROFANE_WILL_LIKELY_REQUIRE_PARTICIPATION                 = 13052,  -- Though tackling the profane will likely require participation of your allies, the objective can be undertaken so long as at least one person has set the appropriate objective.
        WHEN_YOU_SET_THE_OBJECTIVE_AND_COMMENCE_THE                                   = 13053,  -- When you set the objective and commence the battle, the requisite number of Unity accolades will be deducted from your total.
